{
  "name": "Mutual Fund Backtester",
  "description": "Analyze and backtest Indian Mutual Fund portfolios, comparing Direct vs. Regular plan performance to visualize the impact of expense ratios."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum InvestmentType {
  SIP = 'SIP',
  LUMPSUM = 'LUMPSUM'
}

export interface FundDetails {
  name: string;
  category: string;
  expenseRatioDirect: number;
  expenseRatioRegular: number;
  cagr3Y: number; // 3 Year Annualized Return
  lastUpdated: string;
}

export interface Investment {
  id: string;
  fundName: string; // User input name
  details?: FundDetails; // Fetched details
  type: InvestmentType;
  amount: number;
  startDate: string; // ISO Date string
  isLoadingDetails: boolean;
  error?: string;
}

export interface ChartDataPoint {
  month: string;
  directValue: number;
  regularValue: number;
  investedAmount: number;
}

export interface GroundingSource {
  title: string;
  uri: string;
}

export const DEFAULT_CAGR = 12.0; // Fallback if API fails
export const DEFAULT_DIRECT_EXPENSE = 0.8;
export const DEFAULT_REGULAR_EXPENSE = 1.8;

// Colors for charts
export const COLORS = {
  direct: '#10b981', // emerald-500
  regular: '#64748b', // slate-500
  invested: '#94a3b8', // slate-400
};

import { Investment, ChartDataPoint, InvestmentType } from '../types';
import { DEFAULT_CAGR, DEFAULT_DIRECT_EXPENSE, DEFAULT_REGULAR_EXPENSE } from '../constants';

// Helper to calculate future value of a single cash flow
const calculateFV = (principal: number, rate: number, years: number) => {
  return principal * Math.pow(1 + rate, years);
};

export const generateBacktestData = (investments: Investment[]): ChartDataPoint[] => {
  if (investments.length === 0) return [];

  // Find the earliest start date
  const dates = investments.map(i => new Date(i.startDate).getTime());
  const minDate = new Date(Math.min(...dates));
  const now = new Date();

  const dataPoints: ChartDataPoint[] = [];

  // Iterate month by month from start date to now
  let currentDate = new Date(minDate);
  // Align to first of month
  currentDate.setDate(1);

  while (currentDate <= now) {
    let totalDirectValue = 0;
    let totalRegularValue = 0;
    let totalInvested = 0;

    investments.forEach(inv => {
      const invStart = new Date(inv.startDate);
      // If investment hasn't started yet relative to currentDate, skip
      if (invStart > currentDate) return;

      const details = inv.details;
      // Use fetched CAGR or default
      const baseRate = (details?.cagr3Y ?? DEFAULT_CAGR) / 100;

      // Expense ratios
      const terDirect = (details?.expenseRatioDirect ?? DEFAULT_DIRECT_EXPENSE) / 100;
      const terRegular = (details?.expenseRatioRegular ?? DEFAULT_REGULAR_EXPENSE) / 100;

      // Net rates
      const netRateDirect = baseRate - terDirect;
      const netRateRegular = baseRate - terRegular;

      // Years elapsed since investment start *for this specific calculation point*
      // For SIP, we need to sum up cash flows.
      // For Lumpsum, it's just one calculation.

      if (inv.type === InvestmentType.LUMPSUM) {
        const yearsElapsed = (currentDate.getTime() - invStart.getTime()) / (1000 * 60 * 60 * 24 * 365.25);
        totalInvested += inv.amount;
        totalDirectValue += calculateFV(inv.amount, netRateDirect, yearsElapsed);
        totalRegularValue += calculateFV(inv.amount, netRateRegular, yearsElapsed);
      } else {
        // SIP Calculation: approximate by summing monthly contributions
        // Number of months since start
        const monthsSinceStart = (currentDate.getFullYear() - invStart.getFullYear()) * 12 + (currentDate.getMonth() - invStart.getMonth());

        // We iterate through each installment that would have been paid by 'currentDate'
        for (let i = 0; i <= monthsSinceStart; i++) {
            const installmentDate = new Date(invStart);
            installmentDate.setMonth(invStart.getMonth() + i);

            if (installmentDate > currentDate) break;

            const yearsElapsedForInstallment = (currentDate.getTime() - installmentDate.getTime()) / (1000 * 60 * 60 * 24 * 365.25);

            totalInvested += inv.amount;
            totalDirectValue += calculateFV(inv.amount, netRateDirect, yearsElapsedForInstallment);
            totalRegularValue += calculateFV(inv.amount, netRateRegular, yearsElapsedForInstallment);
        }
      }
    });

    dataPoints.push({
      month: currentDate.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
      directValue: Math.round(totalDirectValue),
      regularValue: Math.round(totalRegularValue),
      investedAmount: Math.round(totalInvested)
    });

    // Move to next month
    currentDate.setMonth(currentDate.getMonth() + 1);
  }

  return dataPoints;
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);
};

import { GoogleGenAI, Type, SchemaType } from "@google/genai";
import { FundDetails, GroundingSource } from "../types";

const apiKey = process.env.API_KEY;

// We use the new Gemini 3 Flash model for speed and tool capability
const genAI = new GoogleGenAI({ apiKey });

export const analyzeFund = async (fundName: string): Promise<{ details: FundDetails | null, sources: GroundingSource[] }> => {
  try {
    const model = "gemini-3-flash-preview";

    const prompt = `
      Find the latest 'Direct' and 'Regular' plan expense ratios (TER) and the 3-year annualized return (CAGR) for the Indian mutual fund: "${fundName}".

      If you cannot find the exact 3-year CAGR, use the 1-year or 5-year CAGR but try for 3-year first.

      Return the data strictly in JSON format matching the schema.
    `;

    const response = await genAI.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: {
              type: Type.STRING,
              description: "The official standardized name of the mutual fund scheme.",
            },
            category: {
              type: Type.STRING,
              description: "The category of the fund (e.g., Large Cap, Mid Cap, ELSS).",
            },
            expenseRatioDirect: {
              type: Type.NUMBER,
              description: "The Expense Ratio for the Direct plan (e.g., 0.85).",
            },
            expenseRatioRegular: {
              type: Type.NUMBER,
              description: "The Expense Ratio for the Regular plan (e.g., 1.95).",
            },
            cagr3Y: {
              type: Type.NUMBER,
              description: "The 3-Year Annualized Return percentage (e.g., 15.4).",
            },
          },
          required: ["name", "category", "expenseRatioDirect", "expenseRatioRegular", "cagr3Y"],
        },
      },
    });

    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Source",
        uri: chunk.web?.uri || "#"
      }))
      .filter((s: GroundingSource) => s.uri !== "#") || [];

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        details: {
          ...data,
          lastUpdated: new Date().toISOString()
        },
        sources
      };
    }

    return { details: null, sources: [] };

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    return { details: null, sources: [] };
  }
};

import React from 'react';
import { Investment } from '../types';
import { Trash2, Loader2, TrendingUp, AlertTriangle } from 'lucide-react';
import { formatCurrency } from '../utils/financials';

interface InvestmentListProps {
  investments: Investment[];
  onRemove: (id: string) => void;
}

export const InvestmentList: React.FC<InvestmentListProps> = ({ investments, onRemove }) => {
  if (investments.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-xl border border-dashed border-slate-300">
        <div className="mx-auto h-12 w-12 text-slate-400 flex items-center justify-center rounded-full bg-slate-50 mb-3">
          <TrendingUp size={24} />
        </div>
        <h3 className="text-lg font-medium text-slate-900">No investments added</h3>
        <p className="mt-1 text-sm text-slate-500">Start by adding a mutual fund to your portfolio.</p>
      </div>
    );
  }

  return (
    <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
      {investments.map((inv) => (
        <div key={inv.id} className="bg-white rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow p-5 relative overflow-hidden group">
          <div className="flex justify-between items-start mb-4">
            <div>
              <h4 className="font-semibold text-slate-900 line-clamp-1" title={inv.fundName}>
                {inv.details?.name || inv.fundName}
              </h4>
              <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold mt-1">
                {inv.details?.category || 'Unknown Category'}
              </p>
            </div>
            <button 
              onClick={() => onRemove(inv.id)}
              className="text-slate-400 hover:text-red-500 transition-colors p-1"
            >
              <Trash2 size={18} />
            </button>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-center text-sm">
              <span className="text-slate-500">{inv.type} Amount</span>
              <span className="font-medium text-slate-900">{formatCurrency(inv.amount)}</span>
            </div>
             <div className="flex justify-between items-center text-sm">
              <span className="text-slate-500">Start Date</span>
              <span className="font-medium text-slate-900">{new Date(inv.startDate).toLocaleDateString()}</span>
            </div>

            <div className="pt-3 mt-3 border-t border-slate-100">
               {inv.isLoadingDetails ? (
                <div className="flex items-center text-emerald-600 text-sm">
                  <Loader2 className="animate-spin mr-2 h-4 w-4" />
