                  <div className="bg-emerald-50 p-2 rounded-lg">
                    <span className="block text-emerald-600 font-semibold mb-0.5">Direct TER</span>
                    <span className="text-slate-700 font-bold">{inv.details?.expenseRatioDirect}%</span>
                  </div>
                  <div className="bg-red-50 p-2 rounded-lg">
                    <span className="block text-red-600 font-semibold mb-0.5">Regular TER</span>
                    <span className="text-slate-700 font-bold">{inv.details?.expenseRatioRegular}%</span>
                  </div>
                  <div className="col-span-2 text-center text-slate-400 mt-1">
                    3Y CAGR: <span className="text-slate-700 font-medium">{inv.details?.cagr3Y}%</span>
                  </div>
