import React, { useState } from 'react';
import { InvestmentType } from '../types';
import { PlusCircle, Search } from 'lucide-react';

interface AddInvestmentFormProps {
  onAdd: (fundName: string, type: InvestmentType, amount: number, startDate: string) => void;
  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  const [fundName, setFundName] = useState('');
  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!fundName || !amount || !startDate) return;
    onAdd(fundName, type, parseFloat(amount), startDate);
    // Reset form partially
    setFundName('');
    setAmount('');
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-8">
      <h2 className="text-lg font-semibold text-slate-900 mb-4 flex items-center">
        <PlusCircle className="mr-2 h-5 w-5 text-emerald-600" />
        Add Investment to Backtest
      </h2>
      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
        <div className="lg:col-span-2">
          <label className="block text-sm font-medium text-slate-700 mb-1">Fund Name</label>
          <div className="relative">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search className="h-4 w-4 text-slate-400" />
             </div>
            <input
              type="text"
              value={fundName}
              onChange={(e) => setFundName(e.target.value)}
              placeholder="e.g. HDFC Top 100"
              className="pl-10 w-full rounded-lg border-slate-300 border px-3 py-2 text-sm focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
              required
            />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Type</label>
          <select
            value={type}
            onChange={(e) => setType(e.target.value as InvestmentType)}
            className="w-full rounded-lg border-slate-300 border px-3 py-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
          >
            <option value={InvestmentType.SIP}>SIP (Monthly)</option>
            <option value={InvestmentType.LUMPSUM}>Lumpsum (One-time)</option>
          </select>
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Amount (₹)</label>
          <input
            type="number"
            value={amount}
            onChange={(e) => setAmount(e.target.value)}
            placeholder="5000"
            min="100"
            className="w-full rounded-lg border-slate-300 border px-3 py-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Start Date</label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            max={new Date().toISOString().split('T')[0]}
            className="w-full rounded-lg border-slate-300 border px-3 py-2 text-sm focus:ring-2 focus:ring-emerald-500 outline-none"
            required
          />
        </div>

        <button
          type="submit"
          disabled={isProcessing}
          className="lg:col-span-5 w-full bg-emerald-600 hover:bg-emerald-700 text-white font-medium py-2.5 rounded-lg shadow-sm shadow-emerald-200 transition-all flex justify-center items-center mt-2 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {isProcessing ? (
            <>
              <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2"></div>
              Processing...
            </>
          ) : (
            'Add & Analyze'
          )}
        </button>
      </form>
    </div>
  );
};

import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend
} from 'recharts';
import { ChartDataPoint } from '../types';
import { formatCurrency } from '../utils/financials';
import { COLORS } from '../constants';

interface ComparisonChartProps {
  data: ChartDataPoint[];
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    const direct = payload.find((p: any) => p.dataKey === 'directValue');
    const regular = payload.find((p: any) => p.dataKey === 'regularValue');
    const invested = payload.find((p: any) => p.dataKey === 'investedAmount');

    return (
      <div className="bg-white p-4 border border-slate-100 shadow-xl rounded-lg text-sm">
        <p className="font-bold text-slate-700 mb-2">{label}</p>
        <div className="space-y-1">
           <p className="text-slate-500">
            Invested: <span className="font-semibold text-slate-900">{formatCurrency(invested?.value || 0)}</span>
          </p>
          <p className="text-emerald-600">
            Direct Plan: <span className="font-bold">{formatCurrency(direct?.value || 0)}</span>
          </p>
          <p className="text-slate-500">
            Regular Plan: <span className="font-bold">{formatCurrency(regular?.value || 0)}</span>
          </p>
          <div className="mt-2 pt-2 border-t border-slate-100 text-xs">
            <span className="text-red-500 font-medium">
              Loss: {formatCurrency((direct?.value || 0) - (regular?.value || 0))}
            </span>
          </div>
        </div>
      </div>
    );
  }
  return null;
};

export const ComparisonChart: React.FC<ComparisonChartProps> = ({ data }) => {
  if (!data || data.length === 0) return null;

  return (
    <div className="h-[400px] w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart
          data={data}
          margin={{ top: 10, right: 10, left: 0, bottom: 0 }}
        >
          <defs>
            <linearGradient id="colorDirect" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={COLORS.direct} stopOpacity={0.2} />
              <stop offset="95%" stopColor={COLORS.direct} stopOpacity={0} />
            </linearGradient>
            <linearGradient id="colorRegular" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor={COLORS.regular} stopOpacity={0.2} />
              <stop offset="95%" stopColor={COLORS.regular} stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
          <XAxis 
            dataKey="month" 
            tickLine={false} 
            axisLine={false} 
            tick={{ fill: '#64748b', fontSize: 12 }} 
            minTickGap={30}
          />
          <YAxis 
            tickFormatter={(value) => `₹${(value / 1000).toFixed(0)}k`}
            tickLine={false}
            axisLine={false}
            tick={{ fill: '#64748b', fontSize: 12 }}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend wrapperStyle={{ paddingTop: '20px' }} />
          <Area
            type="monotone"
            dataKey="directValue"
            name="Direct Plan Value"
            stroke={COLORS.direct}
            fillOpacity={1}
            fill="url(#colorDirect)"
            strokeWidth={2}
          />
           <Area
            type="monotone"
            dataKey="regularValue"
            name="Regular Plan Value"
            stroke={COLORS.regular}
            fillOpacity={1}
            fill="url(#colorRegular)"
            strokeWidth={2}
            strokeDasharray="5 5"
          />
          <Area
            type="monotone"
            dataKey="investedAmount"
            name="Total Invested"
            stroke={COLORS.invested}
            fill="transparent"
            strokeWidth={2}
            strokeDasharray="3 3"
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Layout } from './components/Layout';
import { AddInvestmentForm } from './components/AddInvestmentForm';
import { InvestmentList } from './components/InvestmentList';
import { ComparisonChart } from './components/ComparisonChart';
import { Investment, InvestmentType, GroundingSource } from './types';
import { analyzeFund } from './services/geminiService';
import { generateBacktestData, formatCurrency } from './utils/financials';
import { Info, ExternalLink } from 'lucide-react';

const App: React.FC = () => {
  const [investments, setInvestments] = useState<Investment[]>([]);
  const [sources, setSources] = useState<GroundingSource[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('mf_portfolio');
    if (saved) {
      try {
        setInvestments(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved portfolio");
      }
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('mf_portfolio', JSON.stringify(investments));
  }, [investments]);

  const handleAddInvestment = async (fundName: string, type: InvestmentType, amount: number, startDate: string) => {
    const newInvestment: Investment = {
      id: uuidv4(),
      fundName,
      type,
      amount,
      startDate,
      isLoadingDetails: true
    };

    setInvestments(prev => [...prev, newInvestment]);
    setIsProcessing(true);

    try {
      // Call Gemini to fetch details
      const { details, sources: newSources } = await analyzeFund(fundName);

      setSources(prev => {
        const unique = new Map(prev.map(s => [s.uri, s]));
        newSources.forEach(s => unique.set(s.uri, s));
        return Array.from(unique.values());
      });

      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { 
              ...inv, 
              isLoadingDetails: false, 
              details: details || undefined,
              error: details ? undefined : "Could not fetch specific data. Using defaults."
            } 
          : inv
      ));
    } catch (err) {
      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { ...inv, isLoadingDetails: false, error: "Analysis failed. Using defaults." } 
          : inv
      ));
    } finally {
      setIsProcessing(false);
    }
  };

  const removeInvestment = (id: string) => {
    setInvestments(prev => prev.filter(inv => inv.id !== id));
  };

  const chartData = useMemo(() => generateBacktestData(investments), [investments]);

  const stats = useMemo(() => {
    if (chartData.length === 0) return { invested: 0, direct: 0, regular: 0, diff: 0 };
    const lastPoint = chartData[chartData.length - 1];
    return {
      invested: lastPoint.investedAmount,
      direct: lastPoint.directValue,
      regular: lastPoint.regularValue,
      diff: lastPoint.directValue - lastPoint.regularValue
    };
  }, [chartData]);

  return (
    <Layout>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Form and List */}
        <div className="lg:col-span-1 space-y-8">
          <AddInvestmentForm onAdd={handleAddInvestment} isProcessing={isProcessing} />

          <div>
            <h3 className="text-lg font-semibold text-slate-900 mb-4">Your Portfolio</h3>
            <InvestmentList investments={investments} onRemove={removeInvestment} />
          </div>
        </div>

        {/* Right Column: Dashboard and Charts */}
        <div className="lg:col-span-2 space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500 font-medium">Total Invested</p>
              <p className="text-2xl font-bold text-slate-900 mt-1">{formatCurrency(stats.invested)}</p>
            </div>
             <div className="bg-emerald-50 p-5 rounded-xl border border-emerald-100 shadow-sm">
              <p className="text-sm text-emerald-600 font-medium">Est. Direct Value</p>
              <p className="text-2xl font-bold text-emerald-700 mt-1">{formatCurrency(stats.direct)}</p>
            </div>
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-16 h-16 bg-red-100 rounded-bl-full -mr-8 -mt-8"></div>
              <p className="text-sm text-slate-500 font-medium">Extra Cost (Regular)</p>
              <p className="text-2xl font-bold text-red-500 mt-1">{formatCurrency(stats.diff)}</p>
              <p className="text-xs text-slate-400 mt-1">Wealth lost to commissions</p>
            </div>
          </div>

          {/* Chart Area */}
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-semibold text-slate-900">Wealth Projection Backtest</h3>
              <div className="flex items-center space-x-2 text-sm text-slate-500">
                <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
                <span>Direct</span>
                <span className="w-3 h-3 rounded-full bg-slate-500 ml-2"></span>
                <span>Regular</span>
              </div>
            </div>
            {chartData.length > 0 ? (
               <ComparisonChart data={chartData} />
            ) : (
