import { GoogleGenAI, Type, SchemaType } from "@google/genai";
import { FundDetails, GroundingSource } from "../types";

const apiKey = process.env.API_KEY;

// We use the new Gemini 3 Flash model for speed and tool capability
const genAI = new GoogleGenAI({ apiKey });

export const analyzeFund = async (fundName: string): Promise<{ details: FundDetails | null, sources: GroundingSource[] }> => {
  try {
    const model = "gemini-3-flash-preview";

    const prompt = `
      Find the latest 'Direct' and 'Regular' plan expense ratios (TER) and the 3-year annualized return (CAGR) for the Indian mutual fund: "${fundName}".

      If you cannot find the exact 3-year CAGR, use the 1-year or 5-year CAGR but try for 3-year first.

      Also identify the source (website name) where you found the Expense Ratio data (e.g. Value Research, MoneyControl, AMFI).

      Return the data strictly in JSON format matching the schema.
    `;

    const response = await genAI.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: {
              type: Type.STRING,
              description: "The official standardized name of the mutual fund scheme.",
            },
            category: {
              type: Type.STRING,
              description: "The category of the fund (e.g., Large Cap, Mid Cap, ELSS).",
            },
            expenseRatioDirect: {
              type: Type.NUMBER,
              description: "The Expense Ratio for the Direct plan (e.g., 0.85).",
            },
            expenseRatioRegular: {
              type: Type.NUMBER,
              description: "The Expense Ratio for the Regular plan (e.g., 1.95).",
            },
            cagr3Y: {
              type: Type.NUMBER,
              description: "The 3-Year Annualized Return percentage (e.g., 15.4).",
            },
            terSource: {
              type: Type.STRING,
              description: "The name of the website or source where the Expense Ratio was found.",
            },
          },
          required: ["name", "category", "expenseRatioDirect", "expenseRatioRegular", "cagr3Y"],
        },
      },
    });

    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || "Source",
        uri: chunk.web?.uri || "#"
      }))
      .filter((s: GroundingSource) => s.uri !== "#") || [];

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        details: {
          ...data,
          lastUpdated: new Date().toISOString()
        },
        sources
      };
    }

    return { details: null, sources: [] };

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    return { details: null, sources: [] };
  }
};

