// Helper to check if a name looks like a Direct plan
export const isDirectPlan = (name: string): boolean => {
  return name.toLowerCase().includes('direct');
};

// Helper to find the counterpart scheme (Direct <-> Regular)
export const findCounterpartScheme = async (originalCode: string, originalName: string): Promise<MFScheme | null> => {
  const isDirect = isDirectPlan(originalName);

  // Create a search query by removing specific keywords
  // e.g. "HDFC Top 100 Direct Plan Growth" -> "HDFC Top 100 Growth"
  // Then we look for the one that is NOT the original and matches the other type

  let baseName = originalName
    .replace(/Direct Plan/i, '')
    .replace(/Direct/i, '')
    .replace(/Regular Plan/i, '')
    .replace(/Regular/i, '')
    .trim();

  // Remove multiple spaces
  baseName = baseName.replace(/\s\s+/g, ' ');

  const searchResults = await searchMF(baseName);

  if (!searchResults || searchResults.length === 0) return null;

  // Filter strategy
  const candidates = searchResults.filter(s => s.schemeCode !== originalCode);

  // Keywords to match strict options like Growth vs IDCW
  const isGrowth = originalName.toLowerCase().includes('growth');
  const isIDCW = originalName.toLowerCase().includes('idcw') || originalName.toLowerCase().includes('dividend');

  const bestMatch = candidates.find(s => {
    const name = s.schemeName.toLowerCase();

    // Must match option type (Growth/IDCW)
    if (isGrowth && !name.includes('growth')) return false;
    if (isIDCW && !name.includes('idcw') && !name.includes('dividend')) return false;

    // If original was Direct, we want Regular (so NO 'direct' in name)
    // If original was Regular, we want Direct (so YES 'direct' in name)
    if (isDirect) {
      return !name.includes('direct');
    } else {
      return name.includes('direct');
    }
  });

  return bestMatch || null;
};

import { Investment, ChartDataPoint, InvestmentType, NAVData } from '../types';

// Helper to parse dd-mm-yyyy to Date
const parseDate = (dateStr: string): Date => {
  const [d, m, y] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// NAV array is usually sorted descending (newest first).
const getNAVForDate = (history: NAVData[], targetDate: Date, findNextAvailable: boolean = true): number | null => {
  if (!history || history.length === 0) return null;

  const targetTime = targetDate.setHours(0,0,0,0);

  // Find exact
  const exact = history.find(h => parseDate(h.date).getTime() === targetTime);
  if (exact) return parseFloat(exact.nav);

  // If not found...
  if (findNextAvailable) {
    // For purchase: we need the NEXT valid NAV (a date >= targetDate).
    // In a descending list, this means we look from the end (oldest) or filter.
    // We want the smallest date that is >= targetDate.
    // Iterating backwards (oldest to newest) is easier conceptually.
    for (let i = history.length - 1; i >= 0; i--) {
      const d = parseDate(history[i].date);
      if (d.getTime() >= targetTime) {
        return parseFloat(history[i].nav);
      }
    }
    // If we are here, target date is after the last available NAV date (future?)
    return null; 
  } else {
    // For valuation: we need the PREVIOUS valid NAV (value as of date).
    // Date <= targetDate.
    // In descending list, the first item we encounter that is <= target is the one.
    for (let i = 0; i < history.length; i++) {
       const d = parseDate(history[i].date);
       if (d.getTime() <= targetTime) {
         return parseFloat(history[i].nav);
       }
    }
    return null;
  }
};

export const generateBacktestData = (investments: Investment[]): ChartDataPoint[] => {
  if (investments.length === 0) return [];

  const dates = investments.map(i => new Date(i.startDate).getTime());
  const minDate = new Date(Math.min(...dates));
  const now = new Date();

  const dataPoints: ChartDataPoint[] = [];

  // Normalize investments for calculation
  const portfolio = investments.map(inv => ({
    ...inv,
    unitsDirect: 0,
    unitsRegular: 0,
    totalInvested: 0,
    // Identify which history corresponds to Direct vs Regular
    directHistory: inv.isDirect ? inv.navHistory : inv.counterpartNavHistory,
    regularHistory: !inv.isDirect ? inv.navHistory : inv.counterpartNavHistory,
  }));

  let currentDate = new Date(minDate);
  currentDate.setDate(1); // Start from 1st of month

  while (currentDate <= now) {
    let totalDirectValue = 0;
    let totalRegularValue = 0;
    let totalInvestedPortfolio = 0;

    portfolio.forEach(inv => {
      // If investment hasn't started, skip
      const invStart = new Date(inv.startDate);
      if (invStart > currentDate) return;

      const isStartMonth = invStart.getMonth() === currentDate.getMonth() && invStart.getFullYear() === currentDate.getFullYear();

      let shouldInvest = false;
      let investDate = new Date(currentDate);

      if (inv.type === InvestmentType.LUMPSUM) {
        if (isStartMonth && inv.totalInvested === 0) { // Only invest once
           shouldInvest = true;
           investDate = invStart;
        }
      } else {
        // SIP Logic
        shouldInvest = true; 
        if (isStartMonth) investDate = invStart;
        else investDate.setDate(1); // SIP on 1st
      }

      if (shouldInvest) {
         if (inv.type === InvestmentType.LUMPSUM && inv.totalInvested > 0) {
            shouldInvest = false;
         }

         if (shouldInvest) {
             // Get NAVs for purchase
             const navD = inv.directHistory ? getNAVForDate(inv.directHistory, investDate, true) : null;
             const navR = inv.regularHistory ? getNAVForDate(inv.regularHistory, investDate, true) : null;

             if (navD && navR) {
                 inv.unitsDirect += inv.amount / navD;
                 inv.unitsRegular += inv.amount / navR;
                 inv.totalInvested += inv.amount;
             }
         }
      }

      // Calculate Valuation at end of this month
      const valNavD = inv.directHistory ? getNAVForDate(inv.directHistory, currentDate, false) : null;
      const valNavR = inv.regularHistory ? getNAVForDate(inv.regularHistory, currentDate, false) : null;

      if (valNavD && valNavR) {
        totalDirectValue += inv.unitsDirect * valNavD;
        totalRegularValue += inv.unitsRegular * valNavR;
      }
      totalInvestedPortfolio += inv.totalInvested;
    });

    // Only push if we have value (avoid empty starts)
    if (totalInvestedPortfolio > 0) {
        dataPoints.push({
          month: currentDate.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
          directValue: Math.round(totalDirectValue),
          regularValue: Math.round(totalRegularValue),
          investedAmount: Math.round(totalInvestedPortfolio)
        });
    }

    // Next month
    currentDate.setMonth(currentDate.getMonth() + 1);
  }

  return dataPoints;
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);
};

