  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [selectedScheme, setSelectedScheme] = useState<MFScheme | null>(null);

  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      setResults(data.slice(0, 10)); // Limit to 10
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  // Close dropdown on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setResults([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSelectScheme = (scheme: MFScheme) => {
    setSelectedScheme(scheme);
    setQuery(scheme.schemeName);
    setResults([]);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedScheme || !amount || !startDate) return;
    onAdd(selectedScheme, type, parseFloat(amount), startDate);

    // Reset
    setQuery('');
    setSelectedScheme(null);
    setAmount('');
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-8 relative z-20">
      <h2 className="text-lg font-semibold text-slate-900 mb-4 flex items-center">
        <PlusCircle className="mr-2 h-5 w-5 text-emerald-600" />
        Add Investment to Backtest
      </h2>
      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
        <div className="lg:col-span-2 relative" ref={dropdownRef}>
          <label className="block text-sm font-medium text-slate-700 mb-1">Fund Name</label>
          <div className="relative">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                {isSearching ? <Loader2 className="h-4 w-4 text-emerald-500 animate-spin" /> : <Search className="h-4 w-4 text-slate-400" />}
             </div>
            <input
              type="text"
              value={query}
              onChange={(e) => {
                setQuery(e.target.value);
                setSelectedScheme(null); // Clear selection on edit
