              placeholder="Search Fund (e.g. HDFC Top 100)"
              className="pl-10 w-full rounded-lg border-slate-300 border px-3 py-2 text-sm focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all"
