import React, { useState, useEffect, useRef } from 'react';
import { InvestmentType } from '../types';
import { PlusCircle, Search, Loader2, ArrowRightLeft, Edit2, Check, X } from 'lucide-react';
import { searchMF, MFScheme, findCounterpartScheme, isDirectPlan } from '../services/mfApiService';

interface AddInvestmentFormProps {
  onAdd: (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => void;
  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  // Mode: SEARCH or CONFIGURE
  const [step, setStep] = useState<'SEARCH' | 'CONFIGURE'>('SEARCH');

  // Search State
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  // Configuration State
  const [directScheme, setDirectScheme] = useState<MFScheme | null>(null);
  const [regularScheme, setRegularScheme] = useState<MFScheme | null>(null);
  const [investedIn, setInvestedIn] = useState<'DIRECT' | 'REGULAR'>('REGULAR');

  // Edit Mode for specific slots
  const [editingSlot, setEditingSlot] = useState<'DIRECT' | 'REGULAR' | null>(null);

  // Form Fields
  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  // Reset logic
  const resetForm = () => {
    setStep('SEARCH');
    setQuery('');
    setResults([]);
    setDirectScheme(null);
    setRegularScheme(null);
    setAmount('');
    setStartDate('');
    setEditingSlot(null);
  };

  // Search Effect
  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      setResults(data.slice(0, 10));
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  // Outside click handler
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setResults([]);
        // If we were editing a slot and clicked outside, cancel edit
        if (editingSlot) {
            setEditingSlot(null);
            setQuery(''); 
        }
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [editingSlot]);

  const handleInitialSelect = async (scheme: MFScheme) => {
    setQuery('');
    setResults([]);

    const isDirect = isDirectPlan(scheme.schemeName);

    // Set initial slots
    let dScheme: MFScheme | null = isDirect ? scheme : null;
    let rScheme: MFScheme | null = !isDirect ? scheme : null;

    // Set default invested type based on selection
    setInvestedIn(isDirect ? 'DIRECT' : 'REGULAR');

    // Attempt to find counterpart
    try {
      const counterpart = await findCounterpartScheme(scheme.schemeCode, scheme.schemeName);
      if (counterpart) {
        if (isDirect) rScheme = counterpart;
        else dScheme = counterpart;
      }
    } catch (e) {
      console.error("Auto-match failed", e);
    }

    setDirectScheme(dScheme);
    setRegularScheme(rScheme);
    setStep('CONFIGURE');
  };

  const handleSlotSelect = (scheme: MFScheme) => {
    if (editingSlot === 'DIRECT') setDirectScheme(scheme);
    if (editingSlot === 'REGULAR') setRegularScheme(scheme);

    setEditingSlot(null);
    setQuery('');
    setResults([]);
  };

  const startEditingSlot = (slot: 'DIRECT' | 'REGULAR') => {
    setEditingSlot(slot);
    setQuery(''); // Start fresh search
    setTimeout(() => {
        // Focus input logic if we had a ref to the search input
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const investedScheme = investedIn === 'DIRECT' ? directScheme : regularScheme;
    const counterpartScheme = investedIn === 'DIRECT' ? regularScheme : directScheme;

    if (!investedScheme || !amount || !startDate) return;

    onAdd(investedScheme, counterpartScheme, type, parseFloat(amount), startDate);
    resetForm();
  };

  const renderSchemeCard = (label: string, scheme: MFScheme | null, slot: 'DIRECT' | 'REGULAR') => {
    const isSelected = investedIn === slot;
    const isEditing = editingSlot === slot;

    if (isEditing) {
       return (
         <div className="relative" ref={dropdownRef}>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Search {label}</label>
            <div className="relative">
                <input
                    autoFocus
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={`Search ${label}...`}
                    className="w-full rounded-md border-emerald-500 border-2 px-3 py-2 text-sm outline-none"
                />
                 <button 
                    onClick={() => setEditingSlot(null)}
                    className="absolute right-2 top-2 text-slate-400 hover:text-slate-600"
                >
                    <X size={16} />
                </button>
            </div>
            {results.length > 0 && (
                <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto z-50">
                    {results.map((s) => (
                        <div
                            key={s.schemeCode}
                            onClick={() => handleSlotSelect(s)}
                            className="px-3 py-2 hover:bg-emerald-50 cursor-pointer text-xs text-slate-700 border-b border-slate-50"
                        >
                            {s.schemeName}
                            <span className="block text-[10px] text-slate-400">Code: {s.schemeCode}</span>
                        </div>
                    ))}
                </div>
            )}
         </div>
       )
    }

    return (
      <div 
        className={`p-3 rounded-lg border-2 transition-all relative group ${
          isSelected ? 'border-emerald-500 bg-emerald-50/50' : 'border-slate-200 bg-white'
        }`}
        onClick={() => setInvestedIn(slot)}
      >
        <div className="flex justify-between items-start">
            <div className="flex-1 pr-6">
                <p className={`text-xs font-bold uppercase tracking-wider mb-1 ${isSelected ? 'text-emerald-700' : 'text-slate-500'}`}>
                    {label} Plan
                </p>
                {scheme ? (
                    <>
                        <p className="text-sm font-semibold text-slate-900 line-clamp-2">{scheme.schemeName}</p>
                        <p className="text-xs text-slate-400 mt-1 font-mono">Code: {scheme.schemeCode}</p>
                    </>
                ) : (
                    <p className="text-sm italic text-amber-600">No plan selected</p>
                )}
            </div>

            <div className="flex flex-col gap-2">
                 <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center ${isSelected ? 'border-emerald-600 bg-emerald-600' : 'border-slate-300'}`}>
                    {isSelected && <Check size={12} className="text-white" />}
                </div>
            </div>
        </div>

        <button 
            type="button"
            onClick={(e) => {
                e.stopPropagation();
                startEditingSlot(slot);
            }}
            className="absolute top-2 right-2 p-1.5 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-full opacity-0 group-hover:opacity-100 transition-all"
            title="Change Fund"
        >
            <Edit2 size={14} />
        </button>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mb-8 relative z-20">
      <h2 className="text-lg font-semibold text-slate-900 mb-4 flex items-center">
        <PlusCircle className="mr-2 h-5 w-5 text-emerald-600" />
        {step === 'SEARCH' ? 'Add Investment to Backtest' : 'Configure & Compare'}
      </h2>

      {step === 'SEARCH' ? (
        <div className="relative" ref={dropdownRef}>
          <label className="block text-sm font-medium text-slate-700 mb-2">Search Mutual Fund</label>
          <div className="relative">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                {isSearching ? <Loader2 className="h-4 w-4 text-emerald-500 animate-spin" /> : <Search className="h-4 w-4 text-slate-400" />}
             </div>
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Start typing fund name (e.g. Nippon India Small Cap)..."
              className="pl-10 w-full rounded-lg border-slate-300 border px-3 py-3 text-sm focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none transition-all shadow-sm"
              autoFocus
            />
          </div>

          {results.length > 0 && (
            <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-lg shadow-lg mt-1 max-h-60 overflow-y-auto z-50">
              {results.map((scheme) => (
                <div
                  key={scheme.schemeCode}
                  onClick={() => handleInitialSelect(scheme)}
                  className="px-4 py-3 hover:bg-emerald-50 cursor-pointer border-b border-slate-50 last:border-0"
                >
                  <p className="text-sm font-medium text-slate-800">{scheme.schemeName}</p>
                  <p className="text-xs text-slate-400 mt-0.5">Code: {scheme.schemeCode}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
