import { Investment, ChartDataPoint, InvestmentType, NAVData } from '../types';

// Helper to parse dd-mm-yyyy to Date
const parseDate = (dateStr: string): Date => {
  const [d, m, y] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// NAV array is usually sorted descending (newest first).
const getNAVForDate = (history: NAVData[], targetDate: Date, findNextAvailable: boolean = true): number | null => {
  if (!history || history.length === 0) return null;

  const targetTime = targetDate.setHours(0,0,0,0);

  // Find exact
  const exact = history.find(h => parseDate(h.date).getTime() === targetTime);
  if (exact) return parseFloat(exact.nav);

  // If not found...
  if (findNextAvailable) {
    // For purchase: we need the NEXT valid NAV (a date >= targetDate).
    // Iterating backwards (oldest to newest) is easier conceptually.
    for (let i = history.length - 1; i >= 0; i--) {
      const d = parseDate(history[i].date);
      if (d.getTime() >= targetTime) {
        return parseFloat(history[i].nav);
      }
    }
    return null; 
  } else {
    // For valuation: we need the PREVIOUS valid NAV (value as of date).
    // In descending list, the first item we encounter that is <= target is the one.
    for (let i = 0; i < history.length; i++) {
       const d = parseDate(history[i].date);
       if (d.getTime() <= targetTime) {
         return parseFloat(history[i].nav);
       }
    }
    // If we're past the last available date (e.g. asking for today but data is only up to yesterday),
    // we should return the latest available NAV (index 0) if the target date is AFTER the latest date.
    // However, the loop above handles <= target. If target is today and latest data is yesterday, 
    // yesterday <= today, so it returns index 0. This is correct.

    return null;
  }
};

export const generateBacktestData = (investments: Investment[]): ChartDataPoint[] => {
  if (investments.length === 0) return [];

  // Filter out investments that failed to load ANY data
  const activeInvestments = investments.filter(i => 
    (i.navHistory && i.navHistory.length > 0) || 
    (i.counterpartNavHistory && i.counterpartNavHistory.length > 0)
  );

  if (activeInvestments.length === 0) return [];

  const dates = activeInvestments.map(i => new Date(i.startDate).getTime());
  const minDate = new Date(Math.min(...dates));
  const now = new Date();

  const dataPoints: ChartDataPoint[] = [];

  // Normalize investments for calculation
  const portfolio = activeInvestments.map(inv => ({
    ...inv,
    unitsDirect: 0,
    unitsRegular: 0,
    totalInvested: 0,
    // Identify which history corresponds to Direct vs Regular
    // If isDirect is true, navHistory is Direct.
    // If isDirect is false, navHistory is Regular.
    directHistory: inv.isDirect ? inv.navHistory : inv.counterpartNavHistory,
    regularHistory: !inv.isDirect ? inv.navHistory : inv.counterpartNavHistory,
  }));

  let currentDate = new Date(minDate);
  currentDate.setDate(1); // Start from 1st of month

  while (currentDate <= now) {
    let totalDirectValue = 0;
    let totalRegularValue = 0;
    let totalInvestedPortfolio = 0;

    portfolio.forEach(inv => {
      // If investment hasn't started, skip
      const invStart = new Date(inv.startDate);
      if (invStart > currentDate) return;

      const isStartMonth = invStart.getMonth() === currentDate.getMonth() && invStart.getFullYear() === currentDate.getFullYear();

      let shouldInvest = false;
      let investDate = new Date(currentDate);

      if (inv.type === InvestmentType.LUMPSUM) {
        if (isStartMonth && inv.totalInvested === 0) { // Only invest once
           shouldInvest = true;
           investDate = invStart;
        }
      } else {
        // SIP Logic
        shouldInvest = true; 
        if (isStartMonth) investDate = invStart;
        else investDate.setDate(1); // SIP on 1st
      }

      if (shouldInvest) {
         if (inv.type === InvestmentType.LUMPSUM && inv.totalInvested > 0) {
            shouldInvest = false;
         }

         if (shouldInvest) {
             // Calculate independently to handle missing data
             let boughtSomething = false;

             if (inv.directHistory && inv.directHistory.length > 0) {
                 const navD = getNAVForDate(inv.directHistory, investDate, true);
                 if (navD) {
                     inv.unitsDirect += inv.amount / navD;
                     boughtSomething = true;
                 }
             }

             if (inv.regularHistory && inv.regularHistory.length > 0) {
                 const navR = getNAVForDate(inv.regularHistory, investDate, true);
                 if (navR) {
                     inv.unitsRegular += inv.amount / navR;
                     boughtSomething = true;
                 }
             }

             if (boughtSomething) {
                 inv.totalInvested += inv.amount;
             }
         }
      }

      // Calculate Valuation at end of this month
      // For valuation, we fallback to 0 if data missing, preserving the other line
      const valNavD = (inv.directHistory && inv.directHistory.length > 0) 
        ? getNAVForDate(inv.directHistory, currentDate, false) 
        : null;

      const valNavR = (inv.regularHistory && inv.regularHistory.length > 0)
        ? getNAVForDate(inv.regularHistory, currentDate, false)
        : null;

      if (valNavD) totalDirectValue += inv.unitsDirect * valNavD;
      if (valNavR) totalRegularValue += inv.unitsRegular * valNavR;

      totalInvestedPortfolio += inv.totalInvested;
    });

    // Only push if we have invested value
    if (totalInvestedPortfolio > 0) {
        dataPoints.push({
          month: currentDate.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
          directValue: Math.round(totalDirectValue),
          regularValue: Math.round(totalRegularValue),
          investedAmount: Math.round(totalInvestedPortfolio)
        });
    }

    // Next month
    currentDate.setMonth(currentDate.getMonth() + 1);
  }

  return dataPoints;
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);
};

import { Investment, ChartDataPoint, InvestmentType, NAVData } from '../types';

// Helper to parse "dd-mm-yyyy" (API format) to Date object (Local Midnight)
const parseAPIDate = (dateStr: string): Date => {
  const [d, m, y] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// Helper to parse "yyyy-mm-dd" (Input format) to Date object (Local Midnight)
const parseISODate = (dateStr: string): Date => {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// Helper to get NAV avoiding mutation and handling gaps
const getNAV = (history: NAVData[], targetDate: Date, mode: 'PURCHASE' | 'VALUATION'): number | null => {
  if (!history || history.length === 0) return null;

  const targetTime = targetDate.getTime();

  // Note: history is typically sorted Descending (Newest first) by API.

  if (mode === 'PURCHASE') {
    // We need a NAV on or after targetDate.
    // In a descending list, we want the *last* item where date >= targetDate.
    // Iterate backwards (oldest to newest) to find the first valid date >= target.
    for (let i = history.length - 1; i >= 0; i--) {
      const d = parseAPIDate(history[i].date);
      if (d.getTime() >= targetTime) {
        return parseFloat(history[i].nav);
      }
    }

    // Fallback: If target date is very recent (e.g. today/yesterday) and API data is slightly lagged,
    // allow using the latest available NAV (index 0).
    // Only do this if targetDate is after the latest available data date.
    const latestDate = parseAPIDate(history[0].date);
    if (targetTime > latestDate.getTime()) {
        return parseFloat(history[0].nav);
    }

    return null;
  } else {
    // VALUATION
    // We need a NAV on or before targetDate.
    // In a descending list, the first item where date <= targetDate is the one.
    for (const entry of history) {
      const d = parseAPIDate(entry.date);
      if (d.getTime() <= targetTime) {
        return parseFloat(entry.nav);
      }
    }
    return null;
  }
};

export const generateBacktestData = (investments: Investment[]): ChartDataPoint[] => {
  if (investments.length === 0) return [];

  // Filter out completely broken investments
  const activeInvestments = investments.filter(i => 
    (i.navHistory && i.navHistory.length > 0) || 
    (i.counterpartNavHistory && i.counterpartNavHistory.length > 0)
  );

  if (activeInvestments.length === 0) return [];

  // Find the earliest start date
  const startDates = activeInvestments.map(i => parseISODate(i.startDate).getTime());
  const minDate = new Date(Math.min(...startDates));

  // Snap minDate to the 1st of that month
  minDate.setDate(1);
  minDate.setHours(0,0,0,0);

  const now = new Date();
  now.setHours(0,0,0,0);

  const dataPoints: ChartDataPoint[] = [];

  // Initialize portfolio tracking
  const portfolio = activeInvestments.map(inv => ({
    ...inv,
    parsedStartDate: parseISODate(inv.startDate),
    unitsDirect: 0,
    unitsRegular: 0,
    totalInvested: 0,
    hasLumpsumInvested: false
  }));

  // Iterate Month by Month
  let cursorDate = new Date(minDate);

  while (cursorDate <= now) {
    // Determine the "Evaluation Date" for this step.
    // We process transactions for this month, then value the portfolio at the END of this month.
    // If the end of month is in the future, use 'now'.

    const year = cursorDate.getFullYear();
    const month = cursorDate.getMonth();

    // Last day of current cursor month
    let monthEndDate = new Date(year, month + 1, 0); 
    if (monthEndDate > now) monthEndDate = new Date(now);

    // 1. Process Investments for this month
    portfolio.forEach(inv => {
      // Skip if investment hasn't started yet relative to this month's bucket
      // (Check is handled by checking specific transaction dates below)

      let paymentDate: Date | null = null;

      if (inv.type === InvestmentType.SIP) {
        // If this is the start month, pay on Start Date.
        // If this is a later month, pay on the 1st (or start day, but usually SIP backtests assume a fixed date. Let's stick to 1st for simplicity after start, or Start Day).
        // Let's use the Start Date's "Day" for consistency if possible, or fallback to 1st.
        // Standard Simple Backtest: Pay on Start Date for first month, then same Day of month subsequently? 
        // Or just 1st of subsequent months? Let's use 1st for subsequent to align with common calculators, 
        // or better: stick to the specific day of the month provided in start date.

        const startDay = inv.parsedStartDate.getDate();

        // Construct potential payment date for this month
        // Handle edge case: Feb 30th -> Feb 28th/29th
        const paymentDay = startDay;
        const maxDayInMonth = new Date(year, month + 1, 0).getDate();
        const actualDay = Math.min(paymentDay, maxDayInMonth);

        const candidateDate = new Date(year, month, actualDay);

        // Logic:
        // 1. Candidate must be >= Start Date
        // 2. Candidate must be <= Now

        if (candidateDate.getTime() >= inv.parsedStartDate.getTime() && candidateDate <= now) {
            paymentDate = candidateDate;
        }

      } else {
        // LUMPSUM
        // Invest only if this is the month of the start date AND we haven't invested yet
        if (!inv.hasLumpsumInvested) {
             const sameMonth = inv.parsedStartDate.getMonth() === month && inv.parsedStartDate.getFullYear() === year;
             if (sameMonth) {
                 paymentDate = inv.parsedStartDate;
             }
        }
      }

      // Execute Transaction
      if (paymentDate) {
         // Mark lumpsum as done
         if (inv.type === InvestmentType.LUMPSUM) inv.hasLumpsumInvested = true;

         // Try Buying Direct
         if (inv.isDirect && inv.navHistory?.length) {
             const nav = getNAV(inv.navHistory, paymentDate, 'PURCHASE');
             if (nav) {
                 inv.unitsDirect += inv.amount / nav;
             }
         } else if (!inv.isDirect && inv.counterpartNavHistory?.length) {
             // User selected Regular, so counterpart is Direct
             const nav = getNAV(inv.counterpartNavHistory, paymentDate, 'PURCHASE');
             if (nav) {
                 inv.unitsDirect += inv.amount / nav;
             }
         }

         // Try Buying Regular
         if (!inv.isDirect && inv.navHistory?.length) {
             const nav = getNAV(inv.navHistory, paymentDate, 'PURCHASE');
             if (nav) {
                 inv.unitsRegular += inv.amount / nav;
             }
         } else if (inv.isDirect && inv.counterpartNavHistory?.length) {
             // User selected Direct, so counterpart is Regular
             const nav = getNAV(inv.counterpartNavHistory, paymentDate, 'PURCHASE');
             if (nav) {
                 inv.unitsRegular += inv.amount / nav;
             }
         }

         // Track total invested (only once per logical investment transaction)
         // We assume if data is missing for one leg, we still "invested" the money.
         inv.totalInvested += inv.amount;
      }
    });

    // 2. Calculate Valuation at Month End
    let totalDirectVal = 0;
    let totalRegularVal = 0;
    let totalInvested = 0;
    let hasValue = false;

    portfolio.forEach(inv => {
        totalInvested += inv.totalInvested;

        // Value Direct
        const historyD = inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        const unitsD = inv.unitsDirect;
        if (unitsD > 0 && historyD) {
            const nav = getNAV(historyD, monthEndDate, 'VALUATION');
            if (nav) {
                totalDirectVal += unitsD * nav;
                hasValue = true;
            }
        }

        // Value Regular
        const historyR = !inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        const unitsR = inv.unitsRegular;
        if (unitsR > 0 && historyR) {
            const nav = getNAV(historyR, monthEndDate, 'VALUATION');
            if (nav) {
                totalRegularVal += unitsR * nav;
                hasValue = true;
            }
        }
    });

    // 3. Push Data Point
    if (totalInvested > 0) {
        dataPoints.push({
            month: monthEndDate.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
            directValue: Math.round(totalDirectVal),
            regularValue: Math.round(totalRegularVal),
            investedAmount: Math.round(totalInvested)
        });
    }

    // Advance to next month
    cursorDate.setMonth(cursorDate.getMonth() + 1);
    cursorDate.setDate(1); // Ensure we stay on 1st
  }

  return dataPoints;
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);
};

