    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => {
    const isDirect = isDirectPlan(investedScheme.schemeName);

    // Create initial entry
    const newInvestment: Investment = {
      id: uuidv4(),
      schemeCode: investedScheme.schemeCode,
      name: investedScheme.schemeName,
      isDirect,
      type,
      amount,
      startDate,
      navHistory: [],
      counterpartSchemeCode: counterpartScheme?.schemeCode,
      counterpartName: counterpartScheme?.schemeName,
      isLoading: true
    };

    setInvestments(prev => [...prev, newInvestment]);
    setIsProcessing(true);

    try {
      // Fetch Data for Invested Fund
      const mainData = await getMFData(investedScheme.schemeCode);
      if (!mainData) throw new Error("Could not fetch NAV data for selected fund");

      // Fetch Data for Counterpart Fund if it exists
      let counterpartData = null;
      if (counterpartScheme) {
        counterpartData = await getMFData(counterpartScheme.schemeCode);
      }

      setInvestments(prev => prev.map(inv => {
        if (inv.id === newInvestment.id) {
            return {
                ...inv,
                isLoading: false,
                category: mainData.meta.scheme_category,
                fundHouse: mainData.meta.fund_house,
                navHistory: mainData.data,
                counterpartNavHistory: counterpartData?.data || [],
                error: !counterpartData ? "Comparison data unavailable" : undefined
            };
        }
        return inv;
      }));

    } catch (err) {
      console.error(err);
      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { ...inv, isLoading: false, error: "Failed to fetch data." } 
          : inv
      ));
    } finally {
      setIsProcessing(false);
    }
  };

  const removeInvestment = (id: string) => {
    setInvestments(prev => prev.filter(inv => inv.id !== id));
  };

  const updateInvestment = (id: string, amount: number, startDate: string) => {
    setInvestments(prev => prev.map(inv => 
      inv.id === id 
        ? { ...inv, amount, startDate }
        : inv
    ));
  };

  const chartData = useMemo(() => generateBacktestData(investments), [investments]);

  const stats = useMemo(() => {
    if (chartData.length === 0) return { invested: 0, direct: 0, regular: 0, diff: 0 };
    const lastPoint = chartData[chartData.length - 1];
    return {
      invested: lastPoint.investedAmount,
      direct: lastPoint.directValue,
      regular: lastPoint.regularValue,
      diff: lastPoint.directValue - lastPoint.regularValue
    };
  }, [chartData]);

  return (
    <Layout>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-8">
          <AddInvestmentForm onAdd={handleAddInvestment} isProcessing={isProcessing} />

          <div>
            <h3 className="text-lg font-semibold text-slate-900 mb-4">Your Portfolio</h3>
            <InvestmentList 
              investments={investments} 
              onRemove={removeInvestment} 
              onUpdate={updateInvestment}
            />
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500 font-medium">Total Invested</p>
              <p className="text-2xl font-bold text-slate-900 mt-1">{formatCurrency(stats.invested)}</p>
            </div>
             <div className="bg-emerald-50 p-5 rounded-xl border border-emerald-100 shadow-sm">
              <p className="text-sm text-emerald-600 font-medium">Real Direct Value</p>
              <p className="text-2xl font-bold text-emerald-700 mt-1">{formatCurrency(stats.direct)}</p>
            </div>
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-16 h-16 bg-red-100 rounded-bl-full -mr-8 -mt-8"></div>
              <p className="text-sm text-slate-500 font-medium">Opportunity Cost</p>
              <p className="text-2xl font-bold text-red-500 mt-1">{formatCurrency(stats.diff)}</p>
              <p className="text-xs text-slate-400 mt-1">Actual historical difference</p>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-semibold text-slate-900">Historical Wealth Creation</h3>
              <div className="flex items-center space-x-2 text-sm text-slate-500">
                <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
                <span>Direct</span>
                <span className="w-3 h-3 rounded-full bg-blue-500 ml-2"></span>
                <span>Regular</span>
              </div>
            </div>
            {chartData.length > 0 ? (
               <ComparisonChart data={chartData} />
            ) : (
               <div className="h-[400px] flex items-center justify-center bg-slate-50 rounded-lg border border-dashed border-slate-200 text-slate-400">
                 Add investments to view the projection graph
               </div>
            )}
            <div className="mt-4 flex items-start p-3 bg-blue-50 text-blue-700 rounded-lg text-sm">
              <Info className="h-5 w-5 mr-2 flex-shrink-0 mt-0.5" />
              <p>
                This chart shows the <strong>actual</strong> historical performance difference between Direct and Regular plans based on their daily NAV values from the Association of Mutual Funds in India (AMFI).
              </p>
            </div>
          </div>
        </div>
      </div>
    </Layout>
  );
};

