import React, { useState } from 'react';
import { Investment } from '../types';
import { Trash2, Loader2, TrendingUp, AlertTriangle, CheckCircle2, Edit2, Check, X } from 'lucide-react';
import { formatCurrency } from '../utils/financials';

interface InvestmentListProps {
  investments: Investment[];
  onRemove: (id: string) => void;
  onUpdate: (id: string, amount: number, startDate: string) => void;
}

export const InvestmentList: React.FC<InvestmentListProps> = ({ investments, onRemove, onUpdate }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<{amount: string, startDate: string}>({ amount: '', startDate: '' });

  const handleEditClick = (inv: Investment) => {
    setEditingId(inv.id);
    setEditValues({ amount: inv.amount.toString(), startDate: inv.startDate });
  };

  const handleCancel = () => {
    setEditingId(null);
  };

  const handleSave = () => {
    if (editingId && editValues.amount && editValues.startDate) {
      onUpdate(editingId, parseFloat(editValues.amount), editValues.startDate);
      setEditingId(null);
    }
  };

  if (investments.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-xl border border-dashed border-slate-300">
        <div className="mx-auto h-12 w-12 text-slate-400 flex items-center justify-center rounded-full bg-slate-50 mb-3">
          <TrendingUp size={24} />
        </div>
        <h3 className="text-lg font-medium text-slate-900">No investments added</h3>
        <p className="mt-1 text-sm text-slate-500">Start by adding a mutual fund to your portfolio.</p>
      </div>
    );
  }

  return (
    <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
      {investments.map((inv) => {
        const isEditing = editingId === inv.id;

        return (
          <div key={inv.id} className={`bg-white rounded-xl border shadow-sm hover:shadow-md transition-all p-5 relative overflow-hidden group ${isEditing ? 'border-emerald-500 ring-1 ring-emerald-500' : 'border-slate-200'}`}>
            <div className="flex justify-between items-start mb-4">
              <div className="flex-1 pr-2">
                <h4 className="font-semibold text-slate-900 line-clamp-1" title={inv.name}>
                  {inv.name}
                </h4>
                <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold mt-1">
                  {inv.category || inv.fundHouse || 'Mutual Fund'}
                </p>
              </div>
              <div className="flex items-center space-x-1">
                {isEditing ? (
                  <>
                    <button 
                      onClick={handleSave}
                      className="text-emerald-600 hover:bg-emerald-50 p-1.5 rounded transition-colors"
                      title="Save"
                    >
                      <Check size={16} />
                    </button>
                    <button 
                      onClick={handleCancel}
                      className="text-slate-400 hover:bg-slate-50 p-1.5 rounded transition-colors"
                      title="Cancel"
                    >
                      <X size={16} />
                    </button>
                  </>
                ) : (
                  <>
                    <button 
                      onClick={() => handleEditClick(inv)}
                      className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded transition-colors"
                      title="Edit"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => onRemove(inv.id)}
                      className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-1.5 rounded transition-colors"
                      title="Delete"
                    >
                      <Trash2 size={16} />
                    </button>
                  </>
                )}
              </div>
            </div>

            <div className="space-y-3">
              {isEditing ? (
                <div className="space-y-3 bg-slate-50 p-3 rounded-lg -mx-1">
                   <div className="space-y-1">
                      <label className="text-xs font-semibold text-slate-500 block">{inv.type} Amount</label>
                      <input 
                        type="number" 
                        value={editValues.amount}
                        onChange={(e) => setEditValues({...editValues, amount: e.target.value})}
                        className="w-full text-sm px-2 py-1.5 border border-slate-300 rounded focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 outline-none"
                      />
                   </div>
                   <div className="space-y-1">
                      <label className="text-xs font-semibold text-slate-500 block">Start Date</label>
                      <input 
                        type="date" 
                        value={editValues.startDate}
                        onChange={(e) => setEditValues({...editValues, startDate: e.target.value})}
                        className="w-full text-sm px-2 py-1.5 border border-slate-300 rounded focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 outline-none"
                      />
                   </div>
                </div>
              ) : (
                <>
                  <div className="flex justify-between items-center text-sm">
                    <span className="text-slate-500">{inv.type} Amount</span>
                    <span className="font-medium text-slate-900">{formatCurrency(inv.amount)}</span>
                  </div>
                   <div className="flex justify-between items-center text-sm">
                    <span className="text-slate-500">Start Date</span>
                    <span className="font-medium text-slate-900">{new Date(inv.startDate).toLocaleDateString()}</span>
                  </div>
                </>
              )}

              <div className="pt-3 mt-3 border-t border-slate-100">
                 {inv.isLoading ? (
                  <div className="flex items-center text-emerald-600 text-sm">
                    <Loader2 className="animate-spin mr-2 h-4 w-4" />
