                  </div>
                ) : (
                  <div className="space-y-2">
                    <div className="flex items-center justify-between text-xs">
                      <span className={`px-2 py-1 rounded-md font-medium ${inv.isDirect ? 'bg-emerald-50 text-emerald-700' : 'bg-blue-50 text-blue-700'}`}>
                        {inv.isDirect ? 'Direct' : 'Regular'} Plan
                      </span>
                      {inv.counterpartSchemeCode ? (
                          <span className="flex items-center text-slate-500">
                              <CheckCircle2 className="w-3 h-3 mr-1 text-green-500" />
                              Vs {inv.isDirect ? 'Regular' : 'Direct'}
                          </span>
                      ) : (
                          <span className="flex items-center text-amber-500">
                              <AlertTriangle className="w-3 h-3 mr-1" />
