                        {inv.isDirect ? 'Direct' : 'Regular'} Plan
                      </span>
                      {inv.counterpartSchemeCode ? (
                          <span className="flex items-center text-slate-500">
                              <CheckCircle2 className="w-3 h-3 mr-1 text-green-500" />
