                          </span>
                      ) : (
                          <span className="flex items-center text-amber-500">
                              <AlertTriangle className="w-3 h-3 mr-1" />
                              Comparison N/A
                          </span>
                      )}
                    </div>

                    {inv.counterpartName && (
                        <p className="text-[10px] text-slate-400 truncate">
                            Comparing: {inv.counterpartName}
                        </p>
                    )}

                    {inv.error && (
                      <div className="text-xs text-red-500 mt-1">
                          Error: {inv.error}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

