              <p className="text-xs text-slate-500 pb-1">Click a card to filter chart</p>
            </div>
            <InvestmentList 
              investments={investments} 
              onRemove={removeInvestment} 
              onUpdate={updateInvestment}
              selectedId={selectedInvestmentId}
              onSelect={toggleSelection}
            />
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500 font-medium">Total Invested</p>
              <p className="text-2xl font-bold text-slate-900 mt-1">{formatCurrency(stats.invested)}</p>
            </div>
             <div className="bg-emerald-50 p-5 rounded-xl border border-emerald-100 shadow-sm">
              <p className="text-sm text-emerald-600 font-medium">Real Direct Value</p>
              <p className="text-2xl font-bold text-emerald-700 mt-1">{formatCurrency(stats.direct)}</p>
            </div>
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-16 h-16 bg-red-100 rounded-bl-full -mr-8 -mt-8"></div>
              <p className="text-sm text-slate-500 font-medium">Opportunity Cost</p>
              <p className="text-2xl font-bold text-red-500 mt-1">{formatCurrency(stats.diff)}</p>
              <p className="text-xs text-slate-400 mt-1">Actual historical difference</p>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm min-h-[500px]">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
              <div className="flex-1">
                <h3 className="text-lg font-semibold text-slate-900 flex items-center gap-2">
                  Performance: <span className="text-emerald-600 truncate max-w-[200px] sm:max-w-xs">{selectedInvestmentName}</span>
                </h3>
                <p className="text-xs text-slate-400 mt-1">
                   {selectedInvestmentId ? "Showing data for selected fund only" : "Aggregated performance of all funds"}
                </p>
              </div>

              <div className="flex flex-col items-end gap-2">
                <BenchmarkSelector 
                    selectedScheme={benchmarkScheme} 
                    onSelect={handleBenchmarkSelect} 
                />
                <div className="flex items-center space-x-2 text-sm text-slate-500">
                    {selectedInvestmentId && (
                    <button 
