import { Investment, ChartDataPoint, InvestmentType, NAVData } from '../types';

// Helper to parse "dd-mm-yyyy" (API format) to Date object (Local Midnight)
const parseAPIDate = (dateStr: string): Date => {
  const [d, m, y] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// Helper to parse "yyyy-mm-dd" (Input format) to Date object (Local Midnight)
const parseISODate = (dateStr: string): Date => {
  const [y, m, d] = dateStr.split('-').map(Number);
  return new Date(y, m - 1, d);
};

// Helper to get NAV avoiding mutation and handling gaps
const getNAV = (history: NAVData[], targetDate: Date, mode: 'PURCHASE' | 'VALUATION'): number | null => {
  if (!history || history.length === 0) return null;

  const targetTime = targetDate.getTime();

  if (mode === 'PURCHASE') {
    for (let i = history.length - 1; i >= 0; i--) {
      const d = parseAPIDate(history[i].date);
      if (d.getTime() >= targetTime) {
        return parseFloat(history[i].nav);
      }
    }
    const latestDate = parseAPIDate(history[0].date);
    if (targetTime > latestDate.getTime()) {
        return parseFloat(history[0].nav);
    }
    return null;
  } else {
    for (const entry of history) {
      const d = parseAPIDate(entry.date);
      if (d.getTime() <= targetTime) {
        return parseFloat(entry.nav);
      }
    }
    return null;
  }
};

export const generateBacktestData = (
  investments: Investment[], 
  benchmarkHistory?: NAVData[]
): ChartDataPoint[] => {
  if (investments.length === 0) return [];

  const activeInvestments = investments.filter(i => 
    (i.navHistory && i.navHistory.length > 0) || 
    (i.counterpartNavHistory && i.counterpartNavHistory.length > 0)
  );

  if (activeInvestments.length === 0) return [];

  const startDates = activeInvestments.map(i => parseISODate(i.startDate).getTime());
  const minDate = new Date(Math.min(...startDates));
  minDate.setDate(1);
  minDate.setHours(0,0,0,0);

  const now = new Date();
  now.setHours(0,0,0,0);

  const dataPoints: ChartDataPoint[] = [];

  const portfolio = activeInvestments.map(inv => ({
    ...inv,
    parsedStartDate: parseISODate(inv.startDate),
    unitsDirect: 0,
    unitsRegular: 0,
    totalInvested: 0,
    hasLumpsumInvested: false
  }));

  let benchmarkUnits = 0;
  const hasBenchmark = benchmarkHistory && benchmarkHistory.length > 0;

  let cursorDate = new Date(minDate);

  while (cursorDate <= now) {
    const year = cursorDate.getFullYear();
    const month = cursorDate.getMonth();
    let monthEndDate = new Date(year, month + 1, 0); 
    if (monthEndDate > now) monthEndDate = new Date(now);

    portfolio.forEach(inv => {
      let paymentDate: Date | null = null;

      if (inv.type === InvestmentType.SIP) {
        const startDay = inv.parsedStartDate.getDate();
        const paymentDay = startDay;
        const maxDayInMonth = new Date(year, month + 1, 0).getDate();
        const actualDay = Math.min(paymentDay, maxDayInMonth);
        const candidateDate = new Date(year, month, actualDay);

        if (candidateDate.getTime() >= inv.parsedStartDate.getTime() && candidateDate <= now) {
            paymentDate = candidateDate;
        }

      } else {
        if (!inv.hasLumpsumInvested) {
             const sameMonth = inv.parsedStartDate.getMonth() === month && inv.parsedStartDate.getFullYear() === year;
             if (sameMonth) {
                 paymentDate = inv.parsedStartDate;
             }
        }
      }

      if (paymentDate) {
         if (inv.type === InvestmentType.LUMPSUM) inv.hasLumpsumInvested = true;

         // Direct Buy
         if (inv.isDirect && inv.navHistory?.length) {
             const nav = getNAV(inv.navHistory, paymentDate, 'PURCHASE');
             if (nav) inv.unitsDirect += inv.amount / nav;
         } else if (!inv.isDirect && inv.counterpartNavHistory?.length) {
             const nav = getNAV(inv.counterpartNavHistory, paymentDate, 'PURCHASE');
             if (nav) inv.unitsDirect += inv.amount / nav;
         }

         // Regular Buy
         if (!inv.isDirect && inv.navHistory?.length) {
             const nav = getNAV(inv.navHistory, paymentDate, 'PURCHASE');
             if (nav) inv.unitsRegular += inv.amount / nav;
         } else if (inv.isDirect && inv.counterpartNavHistory?.length) {
             const nav = getNAV(inv.counterpartNavHistory, paymentDate, 'PURCHASE');
             if (nav) inv.unitsRegular += inv.amount / nav;
         }

         // Benchmark Buy
         if (hasBenchmark) {
             const bNav = getNAV(benchmarkHistory!, paymentDate, 'PURCHASE');
             if (bNav) {
                 benchmarkUnits += inv.amount / bNav;
             }
         }

         inv.totalInvested += inv.amount;
      }
    });

    let totalDirectVal = 0;
    let totalRegularVal = 0;
    let totalInvested = 0;
    let totalBenchmarkVal = 0;

    portfolio.forEach(inv => {
        totalInvested += inv.totalInvested;

        const historyD = inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        const unitsD = inv.unitsDirect;
        if (unitsD > 0 && historyD) {
            const nav = getNAV(historyD, monthEndDate, 'VALUATION');
            if (nav) totalDirectVal += unitsD * nav;
        }

        const historyR = !inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        const unitsR = inv.unitsRegular;
        if (unitsR > 0 && historyR) {
            const nav = getNAV(historyR, monthEndDate, 'VALUATION');
            if (nav) totalRegularVal += unitsR * nav;
        }
    });

    if (hasBenchmark && benchmarkUnits > 0) {
        const bNav = getNAV(benchmarkHistory!, monthEndDate, 'VALUATION');
        if (bNav) {
            totalBenchmarkVal = benchmarkUnits * bNav;
        }
    }

    if (totalInvested > 0) {
        dataPoints.push({
            month: monthEndDate.toLocaleDateString('en-US', { month: 'short', year: '2-digit' }),
            directValue: Math.round(totalDirectVal),
            regularValue: Math.round(totalRegularVal),
            investedAmount: Math.round(totalInvested),
            benchmarkValue: hasBenchmark ? Math.round(totalBenchmarkVal) : undefined
        });
    }

    cursorDate.setMonth(cursorDate.getMonth() + 1);
    cursorDate.setDate(1); 
  }

  return dataPoints;
};

export const formatCurrency = (amount: number) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    maximumFractionDigits: 0
  }).format(amount);
};

// --- ADVANCED RATIOS ---

interface CashFlow {
  date: Date;
  amount: number; // Negative for outflow, Positive for inflow
}

// Newton-Raphson method to calculate XIRR
export const calculateXIRR = (transactions: CashFlow[], currentValue: number, valuationDate: Date): number => {
  const flows = [...transactions, { date: valuationDate, amount: currentValue }];

  if (flows.length < 2) return 0;

  // Initial guess (10%)
  let rate = 0.1; 

  for (let i = 0; i < 50; i++) { // Max 50 iterations
    let fValue = 0;
    let fDerivative = 0;

    for (const flow of flows) {
      const days = (flow.date.getTime() - flows[0].date.getTime()) / (1000 * 60 * 60 * 24);
      const years = days / 365;

      // Prevent division by zero or negative base issues by clamping rate > -0.99
      const r = Math.max(rate, -0.99); 

      const pvFactor = Math.pow(1 + r, years);
      fValue += flow.amount / pvFactor;
      fDerivative -= (years * flow.amount) / (pvFactor * (1 + r));
    }

    if (Math.abs(fValue) < 1) break; // Precision threshold

    const newRate = rate - fValue / fDerivative;
    if (isNaN(newRate) || !isFinite(newRate)) return 0; // Convergence failure
    rate = newRate;
  }

  return rate * 100; // Return percentage
};

// Calculate Volatility (Annualized Standard Deviation of Returns)
const calculateVolatility = (navHistory: NAVData[], startDate: Date): number => {
    // Filter history after start date
    const history = navHistory
        .map(h => ({ date: parseAPIDate(h.date), nav: parseFloat(h.nav) }))
        .filter(h => h.date >= startDate)
        .sort((a, b) => a.date.getTime() - b.date.getTime()); // Ascending

    if (history.length < 30) return 0;

    const returns = [];
    for (let i = 1; i < history.length; i++) {
        const r = (history[i].nav - history[i - 1].nav) / history[i - 1].nav;
        returns.push(r);
    }

    const mean = returns.reduce((a, b) => a + b, 0) / returns.length;
    const variance = returns.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / returns.length;

    // Annualize (assume 252 trading days)
    return Math.sqrt(variance) * Math.sqrt(252) * 100;
};

// Calculate Beta (Covariance / Variance)
const calculateBeta = (assetHistory: NAVData[], benchmarkHistory: NAVData[], startDate: Date): number => {
    // Create Map for easy lookup
    const assetMap = new Map<string, number>();
    assetHistory.forEach(h => assetMap.set(h.date, parseFloat(h.nav)));

    const benchMap = new Map<string, number>();
    benchmarkHistory.forEach(h => benchMap.set(h.date, parseFloat(h.nav)));

    // Find common dates (start from oldest common after start date)
    const commonDates = benchmarkHistory
        .filter(h => parseAPIDate(h.date) >= startDate && assetMap.has(h.date))
        .map(h => h.date)
        .reverse(); // Ensure ascending order

    if (commonDates.length < 30) return 1; // Default Beta

    const assetReturns: number[] = [];
    const benchReturns: number[] = [];

    for (let i = 1; i < commonDates.length; i++) {
        const prevDate = commonDates[i-1];
        const currDate = commonDates[i];

        const aPrev = assetMap.get(prevDate)!;
        const aCurr = assetMap.get(currDate)!;
        const bPrev = benchMap.get(prevDate)!;
        const bCurr = benchMap.get(currDate)!;

        assetReturns.push((aCurr - aPrev) / aPrev);
        benchReturns.push((bCurr - bPrev) / bPrev);
    }

    const meanA = assetReturns.reduce((a, b) => a + b, 0) / assetReturns.length;
    const meanB = benchReturns.reduce((a, b) => a + b, 0) / benchReturns.length;

    let covariance = 0;
    let varianceB = 0;

    for (let i = 0; i < assetReturns.length; i++) {
        covariance += (assetReturns[i] - meanA) * (benchReturns[i] - meanB);
        varianceB += Math.pow(benchReturns[i] - meanB, 2);
    }

    if (varianceB === 0) return 1;
    return covariance / varianceB;
};

export interface FundRatios {
    name: string;
    invested: number;
    currentValue: number;
    xirr: number;
    volatility: number;
    beta: number;
    alpha: number;
}

export const calculateFundRatios = (
    investments: Investment[], 
    benchmarkHistory?: NAVData[]
): { portfolio: FundRatios, funds: FundRatios[] } => {

    const fundRatios: FundRatios[] = [];
    const now = new Date();

    // Portfolio level aggregators
    const portfolioCashflows: CashFlow[] = [];
    let portfolioCurrentValue = 0;
    let portfolioInvested = 0;

    investments.forEach(inv => {
        // We focus on the "Direct" or "Actual" investment path for ratios
        const history = inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;

        if (!history || history.length === 0) return;

        const invStartDate = parseISODate(inv.startDate);
        const cashflows: CashFlow[] = [];
        let units = 0;
        let invested = 0;

        // Reconstruct transactions for this specific fund
        // This is a simplified version of the main backtest loop for speed
        const cursor = new Date(invStartDate);
        while (cursor <= now) {
            let paymentDate: Date | null = null;
            if (inv.type === InvestmentType.SIP) {
                // Find valid payment date in this month
                const y = cursor.getFullYear();
                const m = cursor.getMonth();
                const d = invStartDate.getDate();
                const candidate = new Date(y, m, d);
                if (candidate >= invStartDate && candidate <= now) paymentDate = candidate;
            } else if (inv.type === InvestmentType.LUMPSUM) {
                if (cursor.getMonth() === invStartDate.getMonth() && cursor.getFullYear() === invStartDate.getFullYear()) {
                     paymentDate = invStartDate;
                }
            }

            if (paymentDate) {
                const nav = getNAV(history, paymentDate, 'PURCHASE');
                if (nav) {
                    units += inv.amount / nav;
                    invested += inv.amount;
                    cashflows.push({ date: paymentDate, amount: -inv.amount });
                    portfolioCashflows.push({ date: paymentDate, amount: -inv.amount });
                }
            }

            if (inv.type === InvestmentType.LUMPSUM) break; // Only once
            cursor.setMonth(cursor.getMonth() + 1);
        }

        const currentNav = getNAV(history, now, 'VALUATION') || 0;
        const currentValue = units * currentNav;

        portfolioCurrentValue += currentValue;
        portfolioInvested += invested;

        // Metrics
        const xirr = calculateXIRR(cashflows, currentValue, now);
        const vol = calculateVolatility(history, invStartDate);

        let beta = 0;
        let alpha = 0;

        if (benchmarkHistory && benchmarkHistory.length > 0) {
            beta = calculateBeta(history, benchmarkHistory, invStartDate);

            // Approximate Alpha: Portfolio Return - (RiskFree + Beta * (Market Return - RiskFree))
            // Simplified Alpha: XIRR_Fund - XIRR_Benchmark (over same period)
            // But standard Alpha is usually Jensen's Alpha based on CAPM. 
            // We'll use a simplified annualized return diff adjusted by Beta for display clarity

            // Let's calc Benchmark XIRR for this specific stream
            const benchCashflows = cashflows.map(c => ({...c})); // Clone dates/amounts
            let bUnits = 0;
            benchCashflows.forEach(cf => {
                const bNav = getNAV(benchmarkHistory, cf.date, 'PURCHASE');
                if (bNav) bUnits += Math.abs(cf.amount) / bNav;
            });
            const bCurrentNav = getNAV(benchmarkHistory, now, 'VALUATION') || 0;
            const bVal = bUnits * bCurrentNav;
            const bXirr = calculateXIRR(benchCashflows, bVal, now);

            // Jensen's Alpha approximation
            // Alpha = Rp - (Rf + Beta * (Rm - Rf))
            // Assuming Rf (Risk Free) ~ 6%
            const rf = 6.0;
            alpha = xirr - (rf + beta * (bXirr - rf));
        }

        fundRatios.push({
            name: inv.name,
            invested,
            currentValue,
            xirr,
            volatility: vol,
            beta,
            alpha
        });
    });

    // Portfolio XIRR
    const portfolioXirr = calculateXIRR(portfolioCashflows, portfolioCurrentValue, now);

    // Portfolio Volatility/Beta is weighted average of components (Simplified)
    // or we can calculate it if we construct a daily NAV series for the whole portfolio (Expensive)
    // We will use Weighted Average for UI responsiveness
    let weightedVol = 0;
    let weightedBeta = 0;
    let weightedAlpha = 0;

    fundRatios.forEach(f => {
        const weight = f.currentValue / portfolioCurrentValue;
        weightedVol += f.volatility * weight;
        weightedBeta += f.beta * weight;
        weightedAlpha += f.alpha * weight;
    });

    return {
        portfolio: {
            name: 'Total Portfolio',
            invested: portfolioInvested,
            currentValue: portfolioCurrentValue,
            xirr: portfolioXirr,
            volatility: weightedVol,
            beta: weightedBeta,
            alpha: weightedAlpha
        },
        funds: fundRatios
    };
};

