import React, { useState, useEffect, useRef } from 'react';
import { Search, X, TrendingUp, Loader2 } from 'lucide-react';
import { searchMF, MFScheme } from '../services/mfApiService';

interface BenchmarkSelectorProps {
  onSelect: (scheme: MFScheme | null) => void;
  selectedScheme: MFScheme | null;
}

export const BenchmarkSelector: React.FC<BenchmarkSelectorProps> = ({ onSelect, selectedScheme }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      // We want to allow ETFs (which track indices) and Index Funds.
      // Usually "Nifty" or "Sensex" searches return ETFs like "Nippon India ETF Nifty 50 BeES".
      // We no longer strictly filter for "growth" only, as ETFs might be named differently, 
      // but we still limit results.
      setResults(data.slice(0, 15));
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const handleSelect = (scheme: MFScheme) => {
    onSelect(scheme);
    setIsOpen(false);
    setQuery('');
  };

  const clearSelection = (e: React.MouseEvent) => {
    e.stopPropagation();
    onSelect(null);
  };

  return (
    <div className="relative" ref={dropdownRef}>
        {!isOpen && !selectedScheme ? (
            <button 
                onClick={() => setIsOpen(true)}
                className="flex items-center text-sm text-violet-600 hover:text-violet-700 hover:bg-violet-50 px-3 py-1.5 rounded-lg transition-colors border border-dashed border-violet-200"
            >
                <TrendingUp size={14} className="mr-2" />
                Add Benchmark (Index / ETF)
            </button>
        ) : !isOpen && selectedScheme ? (
             <div 
                className="flex items-center text-sm bg-violet-50 text-violet-700 px-3 py-1.5 rounded-lg border border-violet-100 cursor-pointer group"
                onClick={() => setIsOpen(true)}
             >
                <span className="font-medium truncate max-w-[200px] mr-2" title={selectedScheme.schemeName}>
                    Vs {selectedScheme.schemeName}
                </span>
                <button onClick={clearSelection} className="text-violet-400 hover:text-violet-700 p-0.5 rounded-full hover:bg-violet-200">
                    <X size={12} />
                </button>
            </div>
        ) : (
            <div className="absolute top-0 right-0 z-50 w-full md:w-80">
                <div className="bg-white rounded-xl shadow-xl border border-slate-200 p-2">
                    <div className="relative">
                        <input
                            autoFocus
                            type="text"
                            value={query}
                            onChange={(e) => setQuery(e.target.value)}
                            placeholder="Search ETF (e.g. Nifty BeES)..."
                            className="w-full pl-8 pr-8 py-2 text-sm border-b border-slate-100 outline-none"
                        />
                        <Search className="absolute left-2 top-2.5 text-slate-400" size={14} />
                        <button onClick={() => setIsOpen(false)} className="absolute right-2 top-2.5 text-slate-400 hover:text-slate-600">
                            <X size={14} />
                        </button>
                    </div>

                    <div className="max-h-60 overflow-y-auto mt-2">
                         {isSearching ? (
                            <div className="flex justify-center p-4">
                                <Loader2 className="animate-spin text-violet-500" size={20} />
                            </div>
                        ) : results.length > 0 ? (
                            results.map(s => (
                                <div 
                                    key={s.schemeCode}
                                    onClick={() => handleSelect(s)}
                                    className="px-3 py-2 hover:bg-violet-50 cursor-pointer rounded-md"
                                >
                                    <p className="text-xs font-medium text-slate-700 line-clamp-2">{s.schemeName}</p>
                                    <p className="text-[10px] text-slate-400">{s.schemeCode}</p>
                                </div>
                            ))
                        ) : query.length > 2 ? (
                            <div className="p-3 text-center text-xs text-slate-400">
                                No funds found. Try "BeES" or "Index"
                            </div>
                        ) : (
                            <div className="p-3 text-center text-xs text-slate-400">
                                Search for ETFs (e.g. "Nifty BeES", "Gold BeES") or Index Funds.
                            </div>
                        )}
                    </div>
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Layout } from './components/Layout';
import { AddInvestmentForm } from './components/AddInvestmentForm';
import { InvestmentList } from './components/InvestmentList';
import { ComparisonChart } from './components/ComparisonChart';
import { BenchmarkSelector } from './components/BenchmarkSelector';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { Investment, InvestmentType, NAVData } from './types';
import { getMFData, isDirectPlan, MFScheme } from './services/mfApiService';
import { generateBacktestData, formatCurrency } from './utils/financials';
import { Info, FilterX, AlertCircle, BarChart3, PieChart } from 'lucide-react';

const App: React.FC = () => {
  const [investments, setInvestments] = useState<Investment[]>([]);
  const [selectedInvestmentId, setSelectedInvestmentId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'CHART' | 'RATIOS'>('CHART');

  // Benchmark State
  const [benchmarkScheme, setBenchmarkScheme] = useState<MFScheme | null>(null);
  const [benchmarkHistory, setBenchmarkHistory] = useState<NAVData[]>([]);

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('mf_portfolio_v2');
    if (saved) {
      try {
        setInvestments(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved portfolio");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mf_portfolio_v2', JSON.stringify(investments));
  }, [investments]);

  // Handle Benchmark Changes
  const handleBenchmarkSelect = async (scheme: MFScheme | null) => {
      setBenchmarkScheme(scheme);
      if (scheme) {
          try {
              const data = await getMFData(scheme.schemeCode);
              if (data) {
                  setBenchmarkHistory(data.data);
              }
          } catch (e) {
              console.error("Failed to fetch benchmark", e);
          }
      } else {
          setBenchmarkHistory([]);
      }
  };

  const handleAddInvestment = async (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => {
    const isDirect = isDirectPlan(investedScheme.schemeName);

    // Create initial entry
    const newInvestment: Investment = {
      id: uuidv4(),
      schemeCode: investedScheme.schemeCode,
      name: investedScheme.schemeName,
      isDirect,
      type,
      amount,
      startDate,
      navHistory: [],
      counterpartSchemeCode: counterpartScheme?.schemeCode,
      counterpartName: counterpartScheme?.schemeName,
      isLoading: true
    };

    setInvestments(prev => [...prev, newInvestment]);
    setIsProcessing(true);

    try {
      // Fetch Data for Invested Fund
      const mainData = await getMFData(investedScheme.schemeCode);
      if (!mainData) throw new Error("Could not fetch NAV data for selected fund");

      // Fetch Data for Counterpart Fund if it exists
      let counterpartData = null;
      if (counterpartScheme) {
        counterpartData = await getMFData(counterpartScheme.schemeCode);
      }

      setInvestments(prev => prev.map(inv => {
        if (inv.id === newInvestment.id) {
            return {
                ...inv,
                isLoading: false,
                category: mainData.meta.scheme_category,
                fundHouse: mainData.meta.fund_house,
                navHistory: mainData.data,
                counterpartNavHistory: counterpartData?.data || [],
                error: !counterpartData ? "Comparison data unavailable" : undefined
            };
        }
        return inv;
      }));

    } catch (err) {
      console.error(err);
      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { ...inv, isLoading: false, error: "Failed to fetch data." } 
          : inv
      ));
    } finally {
      setIsProcessing(false);
    }
  };

  const removeInvestment = (id: string) => {
    setInvestments(prev => prev.filter(inv => inv.id !== id));
    if (selectedInvestmentId === id) {
      setSelectedInvestmentId(null);
    }
  };

  const updateInvestment = (id: string, amount: number, startDate: string) => {
    setInvestments(prev => prev.map(inv => 
      inv.id === id 
        ? { ...inv, amount, startDate }
        : inv
    ));
  };

  const toggleSelection = (id: string) => {
    setSelectedInvestmentId(prev => prev === id ? null : id);
  };

  // Filter data based on selection
  const activeInvestments = useMemo(() => {
    if (selectedInvestmentId) {
      return investments.filter(inv => inv.id === selectedInvestmentId);
    }
    return investments;
  }, [investments, selectedInvestmentId]);

  const chartData = useMemo(() => 
    generateBacktestData(activeInvestments, benchmarkHistory), 
  [activeInvestments, benchmarkHistory]);

  const stats = useMemo(() => {
    if (chartData.length === 0) return { invested: 0, direct: 0, regular: 0, diff: 0, benchmark: 0 };
    const lastPoint = chartData[chartData.length - 1];
    return {
      invested: lastPoint.investedAmount,
      direct: lastPoint.directValue,
      regular: lastPoint.regularValue,
      diff: lastPoint.directValue - lastPoint.regularValue,
      benchmark: lastPoint.benchmarkValue || 0
    };
  }, [chartData]);

  const selectedInvestmentName = useMemo(() => {
    if (!selectedInvestmentId) return 'Entire Portfolio';
    const inv = investments.find(i => i.id === selectedInvestmentId);
    return inv ? inv.name : 'Selected Fund';
  }, [investments, selectedInvestmentId]);

  return (
    <Layout>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-8">
          <AddInvestmentForm onAdd={handleAddInvestment} isProcessing={isProcessing} />

          <div>
            <div className="flex justify-between items-end mb-4">
              <h3 className="text-lg font-semibold text-slate-900">Your Portfolio</h3>
              <p className="text-xs text-slate-500 pb-1">Click a card to filter chart</p>
            </div>
            <InvestmentList 
              investments={investments} 
              onRemove={removeInvestment} 
              onUpdate={updateInvestment}
              selectedId={selectedInvestmentId}
              onSelect={toggleSelection}
            />
          </div>
        </div>

        <div className="lg:col-span-2 space-y-6">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
              <p className="text-sm text-slate-500 font-medium">Total Invested</p>
              <p className="text-2xl font-bold text-slate-900 mt-1">{formatCurrency(stats.invested)}</p>
            </div>
             <div className="bg-emerald-50 p-5 rounded-xl border border-emerald-100 shadow-sm">
              <p className="text-sm text-emerald-600 font-medium">Real Direct Value</p>
              <p className="text-2xl font-bold text-emerald-700 mt-1">{formatCurrency(stats.direct)}</p>
            </div>
             <div className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-16 h-16 bg-red-100 rounded-bl-full -mr-8 -mt-8"></div>
              <p className="text-sm text-slate-500 font-medium">Opportunity Cost</p>
              <p className="text-2xl font-bold text-red-500 mt-1">{formatCurrency(stats.diff)}</p>
              <p className="text-xs text-slate-400 mt-1">Actual historical difference</p>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm min-h-[500px]">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
              <div className="flex-1">
                <h3 className="text-lg font-semibold text-slate-900 flex items-center gap-2">
                  Performance: <span className="text-emerald-600 truncate max-w-[200px] sm:max-w-xs">{selectedInvestmentName}</span>
                </h3>
                <p className="text-xs text-slate-400 mt-1">
                   {selectedInvestmentId ? "Showing data for selected fund only" : "Aggregated performance"}
                </p>
              </div>

              <div className="flex flex-col items-end gap-2">
                <BenchmarkSelector 
                    selectedScheme={benchmarkScheme} 
                    onSelect={handleBenchmarkSelect} 
                />
                <div className="flex items-center space-x-2 text-sm text-slate-500">
                    {selectedInvestmentId && (
                    <button 
                        onClick={() => setSelectedInvestmentId(null)}
                        className="mr-2 flex items-center px-2 py-1 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded text-xs transition-colors"
                    >
                        <FilterX className="w-3 h-3 mr-1" />
                        Reset View
                    </button>
                    )}
                </div>
              </div>
            </div>

            {/* Tab Navigation */}
            <div className="flex space-x-2 mb-6 border-b border-slate-100">
                <button
                    onClick={() => setActiveTab('CHART')}
                    className={`flex items-center px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                        activeTab === 'CHART' 
                        ? 'border-emerald-500 text-emerald-600' 
                        : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-200'
                    }`}
                >
                    <BarChart3 size={16} className="mr-2" />
                    Backtest Chart
                </button>
                <button
                    onClick={() => setActiveTab('RATIOS')}
                    className={`flex items-center px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                        activeTab === 'RATIOS' 
                        ? 'border-emerald-500 text-emerald-600' 
                        : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-200'
                    }`}
                >
                    <PieChart size={16} className="mr-2" />
                    Ratios & Analysis
                </button>
            </div>

            {activeTab === 'CHART' ? (
                <>
                    {chartData.length > 0 ? (
                    <ComparisonChart 
                        data={chartData} 
                        benchmarkName={benchmarkScheme?.schemeName}
                    />
                    ) : (
                    <div className="h-[400px] flex items-center justify-center bg-slate-50 rounded-lg border border-dashed border-slate-200 text-slate-400">
                        Add investments to view the projection graph
                    </div>
                    )}
                    <div className="mt-4 flex items-start p-3 bg-blue-50 text-blue-700 rounded-lg text-sm">
                        <Info className="h-5 w-5 mr-2 flex-shrink-0 mt-0.5" />
                        <div className="space-y-1">
                            <p>
                                This chart shows the <strong>actual</strong> historical performance difference between Direct and Regular plans based on their daily NAV values from AMFI.
                            </p>
                            {benchmarkScheme && (
                                <p className="text-blue-600/80 text-xs">
                                    <AlertCircle size={12} className="inline mr-1" />
                                    Benchmark curve simulates investing the same amount/dates into {benchmarkScheme.schemeName}.
                                </p>
                            )}
                        </div>
                    </div>
                </>
            ) : (
                <AnalysisDashboard 
                    investments={activeInvestments}
                    benchmarkHistory={benchmarkHistory}
                    benchmarkName={benchmarkScheme?.schemeName}
                />
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default App;

