                                <div className="space-y-1 text-slate-600">
                                    <p>
                                        This chart compares the <strong>actual NAV history</strong>. It is not a projection based on assumed percentages.
                                    </p>
                                    {benchmarkScheme && (
                                        <p className="text-slate-500 text-xs">
                                            <AlertCircle size={12} className="inline mr-1" />
                                            Benchmark curve simulates investing the same amount/dates into {benchmarkScheme.schemeName}.
                                        </p>
                                    )}
                                </div>
                            </div>
                        </>
                    ) : (
                        <AnalysisDashboard 
                            investments={activeInvestments}
                            benchmarkHistory={benchmarkHistory}
                            benchmarkName={benchmarkScheme?.schemeName}
                        />
                    )}
                </div>
            </div>
        </div>

        {/* BOTTOM ROW: INVESTMENT LIST */}
        <div className="space-y-6">
            <div className="flex justify-between items-end border-b border-slate-200 pb-4">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Your Portfolio</h3>
                <p className="text-sm text-slate-500 mt-1">Manage your funds and configurations</p>
              </div>
              <div className="flex space-x-2">
                 <input 
                    type="file" 
                    ref={fileInputRef}
                    className="hidden" 
                    accept=".json"
                    onChange={handleFileChange}
                 />
                 <button 
                    onClick={handleImportClick}
                    className="flex items-center px-4 py-2 bg-white border border-slate-200 text-slate-600 hover:text-emerald-600 hover:border-emerald-200 rounded-lg text-sm font-medium transition-all shadow-sm"
                 >
                    <Upload size={16} className="mr-2" /> Import
                 </button>
                 <button 
                    onClick={handleExportPortfolio}
                    className="flex items-center px-4 py-2 bg-white border border-slate-200 text-slate-600 hover:text-emerald-600 hover:border-emerald-200 rounded-lg text-sm font-medium transition-all shadow-sm"
                 >
                    <Download size={16} className="mr-2" /> Export
                 </button>
              </div>
            </div>

            <InvestmentList 
              investments={investments} 
              onRemove={removeInvestment} 
              onUpdate={updateInvestment}
              selectedId={selectedInvestmentId}
              onSelect={toggleSelection}
            />
        </div>

      </div>
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { Investment } from '../types';
import { Trash2, Loader2, TrendingUp, AlertTriangle, CheckCircle2, Edit2, Check, X, Calendar, IndianRupee } from 'lucide-react';
import { formatCurrency } from '../utils/financials';

interface InvestmentListProps {
  investments: Investment[];
  onRemove: (id: string) => void;
  onUpdate: (id: string, amount: number, startDate: string) => void;
  selectedId: string | null;
  onSelect: (id: string) => void;
}

export const InvestmentList: React.FC<InvestmentListProps> = ({ investments, onRemove, onUpdate, selectedId, onSelect }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<{amount: string, startDate: string}>({ amount: '', startDate: '' });

  const handleEditClick = (e: React.MouseEvent, inv: Investment) => {
    e.stopPropagation();
    setEditingId(inv.id);
    setEditValues({ amount: inv.amount.toString(), startDate: inv.startDate });
  };

  const handleCancel = (e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingId(null);
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (editingId && editValues.amount && editValues.startDate) {
      onUpdate(editingId, parseFloat(editValues.amount), editValues.startDate);
      setEditingId(null);
    }
  };

  const handleRemove = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    onRemove(id);
  };

  const handleCardClick = (id: string) => {
    // Only allow selection if not editing
    if (!editingId) {
        onSelect(id);
    }
  };

  if (investments.length === 0) {
    return (
      <div className="text-center py-16 bg-white rounded-2xl border border-dashed border-slate-300 shadow-sm">
        <div className="mx-auto h-16 w-16 text-slate-300 flex items-center justify-center rounded-full bg-slate-50 mb-4">
          <TrendingUp size={32} />
        </div>
        <h3 className="text-lg font-semibold text-slate-900">No investments added</h3>
        <p className="mt-2 text-slate-500 max-w-sm mx-auto">
          Start by adding a mutual fund using the configuration panel above to analyze your portfolio.
        </p>
      </div>
    );
  }

  return (
    <div className="grid gap-6 grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
      {investments.map((inv) => {
        const isEditing = editingId === inv.id;
        const isSelected = selectedId === inv.id;

        return (
          <div 
            key={inv.id} 
            onClick={() => handleCardClick(inv.id)}
            className={`
                group relative bg-white rounded-2xl transition-all duration-300 p-5 cursor-pointer
                ${isEditing 
                    ? 'border-2 border-emerald-500 shadow-lg scale-[1.02] z-10' 
                    : isSelected 
                        ? 'border-2 border-emerald-500 shadow-md ring-4 ring-emerald-50/50' 
                        : 'border border-slate-200 hover:shadow-xl hover:border-emerald-200 hover:-translate-y-1'
                }
            `}
          >
            <div className="flex justify-between items-start mb-4">
              <div className="flex-1 pr-3">
                 <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide mb-2 ${inv.isDirect ? 'bg-emerald-50 text-emerald-700' : 'bg-blue-50 text-blue-700'}`}>
                    {inv.isDirect ? 'Direct' : 'Regular'} Plan
                 </span>
                <h4 className="font-bold text-slate-900 line-clamp-2 leading-tight h-[2.5em]" title={inv.name}>
                  {inv.name}
                </h4>
              </div>

              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-4 right-4 bg-white/90 backdrop-blur-sm p-1 rounded-lg shadow-sm border border-slate-100">
                {isEditing ? (
                  <>
                    <button 
                      onClick={(e) => handleSave(e)}
                      className="text-white bg-emerald-500 hover:bg-emerald-600 p-1.5 rounded-md transition-colors shadow-sm"
                      title="Save"
                    >
                      <Check size={14} />
                    </button>
                    <button 
                      onClick={(e) => handleCancel(e)}
                      className="text-slate-500 hover:bg-slate-100 p-1.5 rounded-md transition-colors"
                      title="Cancel"
                    >
                      <X size={14} />
                    </button>
                  </>
                ) : (
                  <>
                    <button 
                      onClick={(e) => handleEditClick(e, inv)}
                      className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded-md transition-colors"
                      title="Edit"
                    >
                      <Edit2 size={14} />
                    </button>
                    <button 
                      onClick={(e) => handleRemove(e, inv.id)}
                      className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-md transition-colors"
                      title="Delete"
                    >
                      <Trash2 size={14} />
                    </button>
                  </>
                )}
              </div>
            </div>

            <div className="space-y-4">
              {isEditing ? (
                <div className="space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-inner" onClick={(e) => e.stopPropagation()}>
                   <div className="space-y-1.5">
                      <label className="text-xs font-semibold text-slate-500 block">Invested Amount</label>
                      <div className="relative">
                        <IndianRupee size={12} className="absolute left-2.5 top-2.5 text-slate-400"/>
                        <input 
                            type="number" 
                            value={editValues.amount}
                            onChange={(e) => setEditValues({...editValues, amount: e.target.value})}
                            className="w-full text-sm pl-7 pr-2 py-1.5 border border-slate-200 rounded-lg focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none"
                        />
                      </div>
                   </div>
                   <div className="space-y-1.5">
                      <label className="text-xs font-semibold text-slate-500 block">Start Date</label>
                      <input 
                        type="date" 
                        value={editValues.startDate}
                        onChange={(e) => setEditValues({...editValues, startDate: e.target.value})}
                        className="w-full text-sm px-2 py-1.5 border border-slate-200 rounded-lg focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none"
                      />
                   </div>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-slate-50 rounded-lg p-2.5 border border-slate-100">
                    <span className="text-[10px] uppercase font-semibold text-slate-400 block mb-0.5">{inv.type}</span>
                    <span className="font-bold text-slate-900 flex items-center gap-1">
                        <IndianRupee size={12} className="text-slate-400"/> {inv.amount.toLocaleString('en-IN')}
                    </span>
                  </div>
                   <div className="bg-slate-50 rounded-lg p-2.5 border border-slate-100">
                    <span className="text-[10px] uppercase font-semibold text-slate-400 block mb-0.5">Started</span>
                    <span className="font-bold text-slate-900 flex items-center gap-1">
                        <Calendar size={12} className="text-slate-400" /> {new Date(inv.startDate).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: '2-digit' })}
                    </span>
                  </div>
                </div>
              )}

              <div className="pt-3 border-t border-slate-100">
                 {inv.isLoading ? (
                  <div className="flex items-center text-emerald-600 text-xs font-medium bg-emerald-50 px-3 py-2 rounded-lg">
                    <Loader2 className="animate-spin mr-2 h-3 w-3" />
                    Fetching NAV history...
                  </div>
                ) : (
                  <div className="space-y-2">
                    {inv.counterpartSchemeCode ? (
                          <div className="flex items-center text-slate-500 text-xs bg-slate-50 px-2 py-1.5 rounded-md border border-slate-100">
                              <CheckCircle2 className="w-3.5 h-3.5 mr-1.5 text-emerald-500 flex-shrink-0" />
                              <span className="truncate">Comparing vs {inv.isDirect ? 'Regular' : 'Direct'}</span>
                          </div>
                      ) : (
                          <div className="flex items-center text-amber-600 text-xs bg-amber-50 px-2 py-1.5 rounded-md border border-amber-100">
                              <AlertTriangle className="w-3.5 h-3.5 mr-1.5 flex-shrink-0" />
                              Comparison Unavailable
                          </div>
                      )}

                    {inv.error && (
                      <div className="text-xs text-red-500 bg-red-50 px-2 py-1 rounded-md border border-red-100">
                          {inv.error}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* Selection Indicator */}
            {isSelected && (
                <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-2 border-white"></div>
            )}
          </div>
        );
      })}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { InvestmentType } from '../types';
import { PlusCircle, Search, Loader2, ArrowRightLeft, Edit2, Check, X, ChevronRight } from 'lucide-react';
import { searchMF, MFScheme, findCounterpartScheme, isDirectPlan } from '../services/mfApiService';

interface AddInvestmentFormProps {
  onAdd: (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => void;
  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  const [step, setStep] = useState<'SEARCH' | 'CONFIGURE'>('SEARCH');

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [directScheme, setDirectScheme] = useState<MFScheme | null>(null);
  const [regularScheme, setRegularScheme] = useState<MFScheme | null>(null);
  const [investedIn, setInvestedIn] = useState<'DIRECT' | 'REGULAR'>('REGULAR');

  const [editingSlot, setEditingSlot] = useState<'DIRECT' | 'REGULAR' | null>(null);

  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const resetForm = () => {
    setStep('SEARCH');
    setQuery('');
    setResults([]);
    setDirectScheme(null);
    setRegularScheme(null);
    setAmount('');
    setStartDate('');
    setEditingSlot(null);
  };

  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      setResults(data.slice(0, 10));
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setResults([]);
        if (editingSlot) {
            setEditingSlot(null);
            setQuery(''); 
        }
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [editingSlot]);

  const handleInitialSelect = async (scheme: MFScheme) => {
    setQuery('');
    setResults([]);

    const isDirect = isDirectPlan(scheme.schemeName);

    let dScheme: MFScheme | null = isDirect ? scheme : null;
    let rScheme: MFScheme | null = !isDirect ? scheme : null;

    setInvestedIn(isDirect ? 'DIRECT' : 'REGULAR');

    try {
      const counterpart = await findCounterpartScheme(scheme.schemeCode, scheme.schemeName);
      if (counterpart) {
        if (isDirect) rScheme = counterpart;
        else dScheme = counterpart;
      }
    } catch (e) {
      console.error("Auto-match failed", e);
    }

    setDirectScheme(dScheme);
    setRegularScheme(rScheme);
    setStep('CONFIGURE');
  };

  const handleSlotSelect = (scheme: MFScheme) => {
    if (editingSlot === 'DIRECT') setDirectScheme(scheme);
    if (editingSlot === 'REGULAR') setRegularScheme(scheme);

    setEditingSlot(null);
    setQuery('');
    setResults([]);
  };

  const startEditingSlot = (slot: 'DIRECT' | 'REGULAR') => {
    setEditingSlot(slot);
    setQuery(''); 
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const investedScheme = investedIn === 'DIRECT' ? directScheme : regularScheme;
    const counterpartScheme = investedIn === 'DIRECT' ? regularScheme : directScheme;

    if (!investedScheme || !amount || !startDate) return;

    onAdd(investedScheme, counterpartScheme, type, parseFloat(amount), startDate);
    resetForm();
  };

  const renderSchemeCard = (label: string, scheme: MFScheme | null, slot: 'DIRECT' | 'REGULAR') => {
    const isSelected = investedIn === slot;
    const isEditing = editingSlot === slot;

    if (isEditing) {
       return (
         <div className="relative p-1" ref={dropdownRef}>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Search {label}</label>
            <div className="relative">
                <input
                    autoFocus
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={`Search ${label}...`}
                    className="w-full rounded-md border-emerald-500 border-2 px-3 py-2 text-sm outline-none shadow-sm"
                />
                 <button 
                    type="button"
                    onClick={() => setEditingSlot(null)}
                    className="absolute right-2 top-2 text-slate-400 hover:text-slate-600"
                >
                    <X size={16} />
                </button>
            </div>
            {results.length > 0 && (
                <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto z-50">
                    {results.map((s) => (
                        <div
                            key={s.schemeCode}
                            onClick={() => handleSlotSelect(s)}
                            className="px-3 py-2 hover:bg-emerald-50 cursor-pointer text-xs text-slate-700 border-b border-slate-50"
                        >
                            {s.schemeName}
                        </div>
                    ))}
                </div>
            )}
         </div>
       )
    }

    return (
      <div 
        className={`p-4 rounded-xl border-2 transition-all relative group cursor-pointer ${
          isSelected 
          ? 'border-emerald-500 bg-emerald-50/30' 
          : 'border-slate-200 bg-white hover:border-emerald-200'
        }`}
        onClick={() => setInvestedIn(slot)}
      >
        <div className="flex justify-between items-start gap-2">
            <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded ${isSelected ? 'bg-emerald-100 text-emerald-800' : 'bg-slate-100 text-slate-500'}`}>
                        {label}
                    </span>
                    {isSelected && <span className="text-[10px] text-emerald-600 font-medium flex items-center"><Check size={10} className="mr-0.5"/> Selected</span>}
                </div>
                {scheme ? (
                    <p className={`text-sm font-semibold leading-tight line-clamp-2 ${isSelected ? 'text-slate-900' : 'text-slate-600'}`}>
                        {scheme.schemeName}
                    </p>
                ) : (
                    <p className="text-sm italic text-amber-600/80">Select plan manually</p>
                )}
            </div>
        </div>

        <button 
            type="button"
            onClick={(e) => {
                e.stopPropagation();
                startEditingSlot(slot);
            }}
            className="absolute top-2 right-2 p-1.5 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-full opacity-0 group-hover:opacity-100 transition-all"
            title="Change Fund"
        >
            <Edit2 size={12} />
        </button>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative z-20">
      <div className="flex items-center gap-3 mb-6 border-b border-slate-100 pb-4">
        <div className="bg-emerald-100 p-2 rounded-lg text-emerald-700">
            {step === 'SEARCH' ? <Search size={20} /> : <PlusCircle size={20} />}
        </div>
        <div>
            <h2 className="text-lg font-bold text-slate-900 leading-none">
                {step === 'SEARCH' ? 'Find Fund' : 'Configure Investment'}
            </h2>
            <p className="text-xs text-slate-400 mt-1">
                {step === 'SEARCH' ? 'Search AMFI database' : 'Set parameters for backtest'}
            </p>
        </div>
      </div>

      {step === 'SEARCH' ? (
        <div className="relative pb-8" ref={dropdownRef}>
          <div className="relative group">
             <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                {isSearching ? <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" /> : <Search className="h-5 w-5 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />}
             </div>
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="E.g. HDFC Midcap Opportunities..."
              className="pl-11 w-full rounded-xl border-slate-200 border-2 px-4 py-3.5 text-sm focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all shadow-sm"
              autoFocus
            />
          </div>

          {results.length > 0 && (
            <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-xl shadow-2xl mt-2 max-h-72 overflow-y-auto z-50 divide-y divide-slate-50">
              {results.map((scheme) => (
                <div
                  key={scheme.schemeCode}
                  onClick={() => handleInitialSelect(scheme)}
                  className="px-4 py-3 hover:bg-emerald-50 cursor-pointer group flex items-center justify-between"
                >
                  <div>
                    <p className="text-sm font-medium text-slate-700 group-hover:text-emerald-900">{scheme.schemeName}</p>
                    <p className="text-[10px] text-slate-400 mt-0.5">Code: {scheme.schemeCode}</p>
                  </div>
                  <ChevronRight size={16} className="text-slate-300 group-hover:text-emerald-500" />
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">

           <div className="space-y-3">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Select Plan to Invest In</label>
              <div className="grid grid-cols-1 gap-3 relative">
                  {renderSchemeCard('DIRECT', directScheme, 'DIRECT')}
                  {renderSchemeCard('REGULAR', regularScheme, 'REGULAR')}
              </div>
           </div>

           <div className="bg-slate-50 rounded-xl p-4 border border-slate-100 space-y-4">
                <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Investment Type</label>
                    <div className="grid grid-cols-2 gap-2">
                        <button
                            type="button"
                            onClick={() => setType(InvestmentType.SIP)}
                            className={`py-2 text-sm font-medium rounded-lg border transition-all ${type === InvestmentType.SIP ? 'bg-white border-emerald-500 text-emerald-700 shadow-sm' : 'border-transparent text-slate-500 hover:bg-white hover:shadow-sm'}`}
                        >
                            SIP (Monthly)
                        </button>
                        <button
                            type="button"
                            onClick={() => setType(InvestmentType.LUMPSUM)}
                            className={`py-2 text-sm font-medium rounded-lg border transition-all ${type === InvestmentType.LUMPSUM ? 'bg-white border-emerald-500 text-emerald-700 shadow-sm' : 'border-transparent text-slate-500 hover:bg-white hover:shadow-sm'}`}
                        >
                            Lumpsum
                        </button>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Amount (₹)</label>
                    <input
                        type="number"
                        value={amount}
                        onChange={(e) => setAmount(e.target.value)}
                        placeholder="5000"
                        min="100"
                        className="w-full rounded-lg border-slate-200 border px-3 py-2.5 text-sm focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none bg-white"
                        required
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Start Date</label>
                    <input
                        type="date"
                        value={startDate}
                        onChange={(e) => setStartDate(e.target.value)}
                        max={new Date().toISOString().split('T')[0]}
                        className="w-full rounded-lg border-slate-200 border px-3 py-2.5 text-sm focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none bg-white"
                        required
                    />
                </div>
           </div>

           <div className="flex gap-3 pt-2">
               <button
                 type="button"
                 onClick={resetForm}
                 className="flex-1 py-3 bg-white border border-slate-200 text-slate-600 font-medium rounded-xl hover:bg-slate-50 transition-colors text-sm"
               >
                 Cancel
               </button>
               <button
                type="submit"
                disabled={isProcessing || !directScheme || !regularScheme}
                className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-emerald-200 transition-all flex justify-center items-center disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none text-sm"
                >
                {isProcessing ? (
                    <>
                    <Loader2 className="animate-spin mr-2 h-4 w-4" />
                    Crunching Data...
                    </>
                ) : (
                    'Add to Portfolio'
                )}
                </button>
           </div>
        </form>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { InvestmentType } from '../types';
import { PlusCircle, Search, Loader2, ArrowRightLeft, Edit2, Check, X, ChevronRight } from 'lucide-react';
import { searchMF, MFScheme, findCounterpartScheme, isDirectPlan } from '../services/mfApiService';

interface AddInvestmentFormProps {
  onAdd: (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => void;
  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  const [step, setStep] = useState<'SEARCH' | 'CONFIGURE'>('SEARCH');

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [directScheme, setDirectScheme] = useState<MFScheme | null>(null);
  const [regularScheme, setRegularScheme] = useState<MFScheme | null>(null);
  const [investedIn, setInvestedIn] = useState<'DIRECT' | 'REGULAR'>('REGULAR');

  const [editingSlot, setEditingSlot] = useState<'DIRECT' | 'REGULAR' | null>(null);

  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const resetForm = () => {
    setStep('SEARCH');
    setQuery('');
    setResults([]);
    setDirectScheme(null);
    setRegularScheme(null);
    setAmount('');
    setStartDate('');
    setEditingSlot(null);
  };

  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      setResults(data.slice(0, 10));
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setResults([]);
        if (editingSlot) {
            setEditingSlot(null);
            setQuery(''); 
        }
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [editingSlot]);

  const handleInitialSelect = async (scheme: MFScheme) => {
    setQuery('');
    setResults([]);

    const isDirect = isDirectPlan(scheme.schemeName);

    let dScheme: MFScheme | null = isDirect ? scheme : null;
    let rScheme: MFScheme | null = !isDirect ? scheme : null;

    setInvestedIn(isDirect ? 'DIRECT' : 'REGULAR');

    try {
      const counterpart = await findCounterpartScheme(scheme.schemeCode, scheme.schemeName);
      if (counterpart) {
        if (isDirect) rScheme = counterpart;
        else dScheme = counterpart;
      }
    } catch (e) {
      console.error("Auto-match failed", e);
    }

    setDirectScheme(dScheme);
    setRegularScheme(rScheme);
    setStep('CONFIGURE');
  };

  const handleSlotSelect = (scheme: MFScheme) => {
    if (editingSlot === 'DIRECT') setDirectScheme(scheme);
    if (editingSlot === 'REGULAR') setRegularScheme(scheme);

    setEditingSlot(null);
    setQuery('');
    setResults([]);
  };

  const startEditingSlot = (slot: 'DIRECT' | 'REGULAR') => {
    setEditingSlot(slot);
    setQuery(''); 
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const investedScheme = investedIn === 'DIRECT' ? directScheme : regularScheme;
    const counterpartScheme = investedIn === 'DIRECT' ? regularScheme : directScheme;

    if (!investedScheme || !amount || !startDate) return;

    onAdd(investedScheme, counterpartScheme, type, parseFloat(amount), startDate);
    resetForm();
  };

  const renderSchemeCard = (label: string, scheme: MFScheme | null, slot: 'DIRECT' | 'REGULAR') => {
    const isSelected = investedIn === slot;
    const isEditing = editingSlot === slot;

    if (isEditing) {
       return (
         <div className="relative p-1" ref={dropdownRef}>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Search {label}</label>
            <div className="relative">
                <input
                    autoFocus
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={`Search ${label}...`}
                    className="w-full rounded-md border-emerald-500 border-2 px-3 py-2 text-sm outline-none shadow-sm"
                />
                 <button 
                    type="button"
                    onClick={() => setEditingSlot(null)}
                    className="absolute right-2 top-2 text-slate-400 hover:text-slate-600"
                >
                    <X size={16} />
                </button>
            </div>
            {results.length > 0 && (
                <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto z-50">
                    {results.map((s) => (
                        <div
                            key={s.schemeCode}
                            onClick={() => handleSlotSelect(s)}
                            className="px-3 py-2 hover:bg-emerald-50 cursor-pointer text-xs text-slate-700 border-b border-slate-50"
                        >
                            {s.schemeName}
                        </div>
                    ))}
                </div>
            )}
         </div>
       )
    }

    return (
      <div 
        className={`p-4 rounded-xl border-2 transition-all relative group cursor-pointer ${
          isSelected 
          ? 'border-emerald-500 bg-emerald-50/30' 
          : 'border-slate-200 bg-white hover:border-emerald-200'
        }`}
        onClick={() => setInvestedIn(slot)}
      >
        <div className="flex justify-between items-start gap-2">
            <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded ${isSelected ? 'bg-emerald-100 text-emerald-800' : 'bg-slate-100 text-slate-500'}`}>
                        {label}
                    </span>
                    {isSelected && <span className="text-[10px] text-emerald-600 font-medium flex items-center"><Check size={10} className="mr-0.5"/> Selected</span>}
                </div>
                {scheme ? (
                    <p className={`text-sm font-semibold leading-tight line-clamp-2 ${isSelected ? 'text-slate-900' : 'text-slate-600'}`}>
                        {scheme.schemeName}
                    </p>
                ) : (
                    <p className="text-sm italic text-amber-600/80">Select plan manually</p>
                )}
            </div>
        </div>

        <button 
            type="button"
            onClick={(e) => {
                e.stopPropagation();
                startEditingSlot(slot);
            }}
            className="absolute top-2 right-2 p-1.5 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-full opacity-0 group-hover:opacity-100 transition-all"
            title="Change Fund"
        >
            <Edit2 size={12} />
        </button>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative z-20 h-full">
      <div className="flex items-center gap-3 mb-6 border-b border-slate-100 pb-4">
        <div className="bg-emerald-100 p-2 rounded-lg text-emerald-700">
            {step === 'SEARCH' ? <Search size={20} /> : <PlusCircle size={20} />}
        </div>
        <div>
            <h2 className="text-lg font-bold text-slate-900 leading-none">
                {step === 'SEARCH' ? 'Find Fund' : 'Configure Investment'}
            </h2>
            <p className="text-xs text-slate-400 mt-1">
                {step === 'SEARCH' ? 'Search AMFI database' : 'Set parameters for backtest'}
            </p>
        </div>
      </div>

      {step === 'SEARCH' ? (
        <div className="relative pb-8" ref={dropdownRef}>
          <div className="relative group">
             <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                {isSearching ? <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" /> : <Search className="h-5 w-5 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />}
             </div>
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="E.g. HDFC Midcap Opportunities..."
              className="pl-11 w-full rounded-xl border-slate-200 border-2 px-4 py-3.5 text-sm focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all shadow-sm"
              autoFocus
            />
          </div>

          {results.length > 0 && (
            <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-xl shadow-2xl mt-2 max-h-72 overflow-y-auto z-50 divide-y divide-slate-50">
              {results.map((scheme) => (
                <div
                  key={scheme.schemeCode}
                  onClick={() => handleInitialSelect(scheme)}
                  className="px-4 py-3 hover:bg-emerald-50 cursor-pointer group flex items-center justify-between"
                >
                  <div>
                    <p className="text-sm font-medium text-slate-700 group-hover:text-emerald-900">{scheme.schemeName}</p>
                    <p className="text-[10px] text-slate-400 mt-0.5">Code: {scheme.schemeCode}</p>
                  </div>
                  <ChevronRight size={16} className="text-slate-300 group-hover:text-emerald-500" />
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">

           <div className="space-y-3">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Select Plan to Invest In</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 relative">
                  {renderSchemeCard('DIRECT', directScheme, 'DIRECT')}
                  {renderSchemeCard('REGULAR', regularScheme, 'REGULAR')}
              </div>
           </div>

           <div className="bg-slate-50 rounded-xl p-4 border border-slate-100 space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Investment Type</label>
                        <div className="grid grid-cols-2 gap-2">
                            <button
                                type="button"
                                onClick={() => setType(InvestmentType.SIP)}
                                className={`py-2 text-sm font-medium rounded-lg border transition-all ${type === InvestmentType.SIP ? 'bg-white border-emerald-500 text-emerald-700 shadow-sm' : 'border-transparent text-slate-500 hover:bg-white hover:shadow-sm'}`}
                            >
                                SIP
                            </button>
                            <button
                                type="button"
                                onClick={() => setType(InvestmentType.LUMPSUM)}
                                className={`py-2 text-sm font-medium rounded-lg border transition-all ${type === InvestmentType.LUMPSUM ? 'bg-white border-emerald-500 text-emerald-700 shadow-sm' : 'border-transparent text-slate-500 hover:bg-white hover:shadow-sm'}`}
                            >
                                Lumpsum
                            </button>
                        </div>
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Amount (₹)</label>
                        <input
                            type="number"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            placeholder="5000"
                            min="100"
                            className="w-full rounded-lg border-slate-200 border px-3 py-2.5 text-sm focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none bg-white"
                            required
                        />
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-500 mb-1.5 uppercase">Start Date</label>
                        <input
                            type="date"
                            value={startDate}
                            onChange={(e) => setStartDate(e.target.value)}
                            max={new Date().toISOString().split('T')[0]}
                            className="w-full rounded-lg border-slate-200 border px-3 py-2.5 text-sm focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none bg-white"
                            required
                        />
                    </div>
                </div>
           </div>

           <div className="flex gap-3 pt-2">
               <button
                 type="button"
                 onClick={resetForm}
                 className="flex-1 py-3 bg-white border border-slate-200 text-slate-600 font-medium rounded-xl hover:bg-slate-50 transition-colors text-sm"
               >
                 Cancel
               </button>
               <button
                type="submit"
                disabled={isProcessing || !directScheme || !regularScheme}
                className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl shadow-lg shadow-emerald-200 transition-all flex justify-center items-center disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none text-sm"
                >
                {isProcessing ? (
                    <>
                    <Loader2 className="animate-spin mr-2 h-4 w-4" />
                    Crunching Data...
                    </>
                ) : (
                    'Add to Portfolio'
                )}
                </button>
           </div>
        </form>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Layout } from './components/Layout';
import { AddInvestmentForm } from './components/AddInvestmentForm';
import { InvestmentList } from './components/InvestmentList';
import { ComparisonChart } from './components/ComparisonChart';
import { BenchmarkSelector } from './components/BenchmarkSelector';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { Investment, InvestmentType, NAVData } from './types';
import { getMFData, isDirectPlan, MFScheme } from './services/mfApiService';
import { generateBacktestData, formatCurrency } from './utils/financials';
import { Info, FilterX, AlertCircle, BarChart3, PieChart, Download, Upload, TrendingUp, DollarSign, Wallet } from 'lucide-react';

const App: React.FC = () => {
  const [investments, setInvestments] = useState<Investment[]>([]);
  const [selectedInvestmentId, setSelectedInvestmentId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'CHART' | 'RATIOS'>('CHART');

  // Benchmark State
  const [benchmarkScheme, setBenchmarkScheme] = useState<MFScheme | null>(null);
  const [benchmarkHistory, setBenchmarkHistory] = useState<NAVData[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('mf_portfolio_v2');
    if (saved) {
      try {
        setInvestments(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved portfolio");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mf_portfolio_v2', JSON.stringify(investments));
  }, [investments]);

  // Handle Benchmark Changes
  const handleBenchmarkSelect = async (scheme: MFScheme | null) => {
      setBenchmarkScheme(scheme);
      if (scheme) {
          try {
              const data = await getMFData(scheme.schemeCode);
              if (data) {
                  setBenchmarkHistory(data.data);
              }
          } catch (e) {
              console.error("Failed to fetch benchmark", e);
          }
      } else {
          setBenchmarkHistory([]);
      }
  };

  const handleExportPortfolio = () => {
    const dataStr = JSON.stringify(investments, null, 2);
    const blob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `mf-portfolio-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const parsedData = JSON.parse(content);
        if (Array.isArray(parsedData)) {
            const isValid = parsedData.every(item => item.id && item.schemeCode && item.amount);
            if (isValid) {
                setInvestments(parsedData);
            } else {
                alert("Invalid portfolio file format.");
            }
        }
      } catch (error) {
        console.error("Error parsing file", error);
        alert("Failed to read portfolio file.");
      }
    };
    reader.readAsText(file);
    event.target.value = ''; // Reset
  };

  const handleAddInvestment = async (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string
  ) => {
    const isDirect = isDirectPlan(investedScheme.schemeName);

    // Create initial entry
    const newInvestment: Investment = {
      id: uuidv4(),
      schemeCode: investedScheme.schemeCode,
      name: investedScheme.schemeName,
      isDirect,
      type,
      amount,
      startDate,
      navHistory: [],
      counterpartSchemeCode: counterpartScheme?.schemeCode,
      counterpartName: counterpartScheme?.schemeName,
      isLoading: true
    };

    setInvestments(prev => [...prev, newInvestment]);
    setIsProcessing(true);

    try {
      const mainData = await getMFData(investedScheme.schemeCode);
      if (!mainData) throw new Error("Could not fetch NAV data for selected fund");

      let counterpartData = null;
      if (counterpartScheme) {
        counterpartData = await getMFData(counterpartScheme.schemeCode);
      }

      setInvestments(prev => prev.map(inv => {
        if (inv.id === newInvestment.id) {
            return {
                ...inv,
                isLoading: false,
                category: mainData.meta.scheme_category,
                fundHouse: mainData.meta.fund_house,
                navHistory: mainData.data,
                counterpartNavHistory: counterpartData?.data || [],
                error: !counterpartData ? "Comparison data unavailable" : undefined
            };
        }
        return inv;
      }));

    } catch (err) {
      console.error(err);
      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { ...inv, isLoading: false, error: "Failed to fetch data." } 
          : inv
      ));
    } finally {
      setIsProcessing(false);
    }
  };

  const removeInvestment = (id: string) => {
    setInvestments(prev => prev.filter(inv => inv.id !== id));
    if (selectedInvestmentId === id) {
      setSelectedInvestmentId(null);
    }
  };

  const updateInvestment = (id: string, amount: number, startDate: string) => {
    setInvestments(prev => prev.map(inv => 
      inv.id === id 
        ? { ...inv, amount, startDate }
        : inv
    ));
  };

  const toggleSelection = (id: string) => {
    setSelectedInvestmentId(prev => prev === id ? null : id);
  };

  // Filter data based on selection
  const activeInvestments = useMemo(() => {
    if (selectedInvestmentId) {
      return investments.filter(inv => inv.id === selectedInvestmentId);
    }
    return investments;
  }, [investments, selectedInvestmentId]);

  const chartData = useMemo(() => 
    generateBacktestData(activeInvestments, benchmarkHistory), 
  [activeInvestments, benchmarkHistory]);

  const stats = useMemo(() => {
    if (chartData.length === 0) return { invested: 0, direct: 0, regular: 0, diff: 0, benchmark: 0 };
    const lastPoint = chartData[chartData.length - 1];
    return {
      invested: lastPoint.investedAmount,
      direct: lastPoint.directValue,
      regular: lastPoint.regularValue,
      diff: lastPoint.directValue - lastPoint.regularValue,
      benchmark: lastPoint.benchmarkValue || 0
    };
  }, [chartData]);

  const selectedInvestmentName = useMemo(() => {
    if (!selectedInvestmentId) return 'Entire Portfolio';
    const inv = investments.find(i => i.id === selectedInvestmentId);
    return inv ? inv.name : 'Selected Fund';
  }, [investments, selectedInvestmentId]);

  return (
    <Layout>
      <div className="space-y-12">

        {/* SECTION 1: ADD FUNDS */}
        <section>
             <div className="flex items-end justify-between mb-4">
                 <div>
                    <h3 className="text-xl font-bold text-slate-900">Build Your Portfolio</h3>
                    <p className="text-sm text-slate-500">Search and add mutual funds to backtest</p>
                 </div>
                 <div className="hidden md:block text-xs text-slate-400 max-w-md text-right">
                    We automatically find Direct/Regular plan counterparts to compare true costs.
                 </div>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-stretch">
                <div className="lg:col-span-8">
                     <AddInvestmentForm onAdd={handleAddInvestment} isProcessing={isProcessing} />
                </div>
                <div className="hidden lg:block lg:col-span-4">
                    <div className="bg-blue-50/50 border border-blue-100 rounded-2xl p-6 h-full flex flex-col justify-center">
                        <div className="mb-4 bg-white w-12 h-12 rounded-xl flex items-center justify-center shadow-sm text-blue-600">
                            <Info size={24} />
                        </div>
                        <h4 className="font-bold text-blue-900 text-lg mb-2">How it works</h4>
                        <p className="text-blue-800/80 text-sm leading-relaxed mb-4">
                            1. <strong>Search</strong> for any fund (e.g. "SBI Small Cap").<br/>
                            2. We <strong>auto-detect</strong> if it's Direct or Regular and find its pair.<br/>
                            3. Set your <strong>SIP or Lumpsum</strong> amount and date.<br/>
                            4. We crunch daily NAV data to show the <strong>real</strong> difference.
                        </p>
                        <div className="text-xs text-blue-400 font-medium">
                            Powered by daily AMFI NAV data
                        </div>
                    </div>
                </div>
             </div>
        </section>

        {/* SECTION 2: PORTFOLIO LIST */}
        <section>
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b border-slate-200 pb-4 mb-6 gap-4">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Your Holdings</h3>
                <p className="text-sm text-slate-500 mt-1">Manage {investments.length} active investments</p>
              </div>
              <div className="flex space-x-2">
                 <input 
                    type="file" 
                    ref={fileInputRef}
                    className="hidden" 
                    accept=".json"
                    onChange={handleFileChange}
                 />
                 <button 
                    onClick={handleImportClick}
                    className="flex items-center px-4 py-2 bg-white border border-slate-200 text-slate-600 hover:text-emerald-600 hover:border-emerald-200 rounded-lg text-sm font-medium transition-all shadow-sm"
                 >
                    <Upload size={16} className="mr-2" /> Import
                 </button>
                 <button 
                    onClick={handleExportPortfolio}
                    className="flex items-center px-4 py-2 bg-white border border-slate-200 text-slate-600 hover:text-emerald-600 hover:border-emerald-200 rounded-lg text-sm font-medium transition-all shadow-sm"
                 >
                    <Download size={16} className="mr-2" /> Export
                 </button>
              </div>
            </div>

            <InvestmentList 
              investments={investments} 
              onRemove={removeInvestment} 
              onUpdate={updateInvestment}
              selectedId={selectedInvestmentId}
              onSelect={toggleSelection}
            />
        </section>

        {/* SECTION 3: PERFORMANCE */}
        <section>
            <h3 className="text-xl font-bold text-slate-900 mb-6">Performance Comparison</h3>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between group hover:border-emerald-100 transition-colors">
                    <div>
                        <p className="text-sm text-slate-500 font-medium mb-1 flex items-center gap-1">
                        <Wallet size={14} /> Total Invested
                        </p>
                        <p className="text-3xl font-bold text-slate-900">{formatCurrency(stats.invested)}</p>
                    </div>
                    <div className="h-12 w-12 bg-slate-50 rounded-full flex items-center justify-center text-slate-400 group-hover:bg-emerald-50 group-hover:text-emerald-500 transition-colors">
                        <DollarSign size={24} />
                    </div>
                </div>

                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex items-center justify-between group hover:border-emerald-100 transition-colors">
