export const calculatePortfolioStats = (
    investments: Investment[],
    chartData: ChartDataPoint[],
    benchmarkHistory?: NAVData[]
): PortfolioMetrics => {
    // Basic Sums
    let totalInvested = 0;
    let currentValueDirect = 0;
    let currentValueRegular = 0;
    const cashFlows: CashFlow[] = [];

    // Calculate aggregated cashflows for XIRR
    // Note: We need accurate daily cashflows for XIRR. 
    // Re-simulating simply to get cashflow array

    investments.forEach(inv => {
        const startDate = parseISODate(inv.startDate);
        const now = new Date();

        // Simulating SIPs/Lumpsum to get cashflows
        if (inv.type === InvestmentType.LUMPSUM) {
             totalInvested += inv.amount;
             cashFlows.push({ date: startDate, amount: -inv.amount });
        } else {
             // SIP
             let cursor = new Date(startDate);
             while (cursor <= now) {
                totalInvested += inv.amount;
                cashFlows.push({ date: new Date(cursor), amount: -inv.amount });
                cursor.setMonth(cursor.getMonth() + 1);
             }
        }
    });

    // Get current values from last chart data point
    if (chartData.length > 0) {
        const last = chartData[chartData.length - 1];
        currentValueDirect = last.directValue;
        currentValueRegular = last.regularValue;
    }

    // XIRR
    const xirr = calculateXIRR(cashFlows, currentValueDirect, new Date());

    // Absolute Return
    const absoluteReturn = totalInvested > 0 
        ? ((currentValueDirect - totalInvested) / totalInvested) * 100 
        : 0;

    // Max Drawdown (using Chart Data Portfolio Value curve)
    // We use the directValue curve
    const portfolioValues = chartData.map(d => d.directValue);
    const maxDrawdown = calculateMaxDrawdown(portfolioValues);

    // RoMaD (Return on Max Drawdown)
    // Using XIRR / MaxDrawdown. (If MaxDD is 0, RoMaD is infinite/capped)
    // Since MaxDrawdown is a risk, a lower number is better. 
    // RoMaD = Return / Risk.
    const romad = maxDrawdown > 0 ? xirr / maxDrawdown : (xirr > 0 ? 100 : 0); 

    // Alpha & Beta (If Benchmark exists)
    let alpha = 0;
    let beta = 0;

    if (benchmarkHistory && benchmarkHistory.length > 0 && chartData.length > 6) {
        // Calculate Portfolio Beta roughly using the monthly data points
        // CRITICAL: We must adjust for cashflows (SIPs) to get the true "Investment Return" for the period
        // Otherwise, a SIP deposit looks like a massive market gain.

        const portfolioReturns = [];
        const benchmarkReturns = [];

        for (let i = 1; i < chartData.length; i++) {
             const prev = chartData[i-1];
             const curr = chartData[i];

             // Calculate Net Flow for the month (New Investment)
             const cashflow = curr.investedAmount - prev.investedAmount;

             if(prev.directValue > 0 && prev.benchmarkValue !== undefined && curr.benchmarkValue !== undefined) {
                 // Return = (EndValue - StartValue - NetFlow) / (StartValue + NetFlow)
                 // Denominator assumes cashflow contributes to the base. 
                 // This effectively isolates the "Market Gain" component.

                 const pDenom = prev.directValue + cashflow;
                 const pRet = pDenom > 0 ? (curr.directValue - prev.directValue - cashflow) / pDenom : 0;

                 // Benchmark Value in chartData is also a simulation with the SAME cashflows
                 // So we treat it identically to ensure apples-to-apples comparison of the STRATEGY
                 const bDenom = prev.benchmarkValue + cashflow;
                 const bRet = bDenom > 0 ? (curr.benchmarkValue - prev.benchmarkValue - cashflow) / bDenom : 0;

                 portfolioReturns.push(pRet);
                 benchmarkReturns.push(bRet);
             }
        }

        if (portfolioReturns.length > 0) {
            const meanPort = portfolioReturns.reduce((a,b) => a+b, 0) / portfolioReturns.length;
            const meanBench = benchmarkReturns.reduce((a,b) => a+b, 0) / benchmarkReturns.length;

            let cov = 0;
            let varBench = 0;
            for(let i=0; i<portfolioReturns.length; i++) {
                cov += (portfolioReturns[i] - meanPort) * (benchmarkReturns[i] - meanBench);
                varBench += Math.pow(benchmarkReturns[i] - meanBench, 2);
            }

            beta = varBench > 0 ? cov / varBench : 1;

            // Jensen's Alpha (Annualized)
            // Alpha = Rp - (Rf + Beta * (Rm - Rf))
            // Assuming Rf (Risk Free) = 6%
            const rf = 0.06;

            // For Rm (Market Return), we use the CAGR of the Benchmark Simulation over the period
            // This represents the "SIP Market Return"
            const startVal = chartData[0].benchmarkValue || 1;
            const endVal = chartData[chartData.length-1].benchmarkValue || 1;

            // We need to calculate Internal Rate of Return (IRR) for the benchmark simulation 
            // to get a true annualized Rm compatible with the Portfolio XIRR.
            // However, calculating XIRR for benchmark again is expensive.
            // Let's approximate Rm using the mean monthly return annualized.
            // Rm_annual ~ (1 + meanBench)^12 - 1
            const rm = Math.pow(1 + meanBench, 12) - 1;

            // Using XIRR for Rp is more accurate than mean monthly return for the portfolio
            const rp = xirr / 100;

            alpha = rp - (rf + beta * (rm - rf));
            alpha = alpha * 100; // to percentage
        }
    }

    return {
        totalInvested,
        currentValue: currentValueDirect,
        regularValue: currentValueRegular,
        xirr,
        absoluteReturn,
        maxDrawdown,
        romad,
        alpha: benchmarkHistory ? alpha : undefined,
        beta: benchmarkHistory ? beta : undefined
    };
};

// Existing fund-level calculator for the dashboard table
export const calculateFundRatios = (investments: Investment[], benchmarkHistory: NAVData[]) => {
    // Calculate for individual funds
    const funds = investments.map(inv => {
        const history = inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        if (!history || history.length === 0) return null;

        const startDate = parseISODate(inv.startDate);
        const cashFlows: CashFlow[] = [];
        let units = 0;
        let invested = 0;
        const now = new Date();

        if (inv.type === InvestmentType.LUMPSUM) {
             const nav = getNAV(history, startDate, 'PURCHASE');
             if (nav) units += inv.amount / nav;
             cashFlows.push({ date: startDate, amount: -inv.amount });
             invested += inv.amount;
        } else {
             let cursor = new Date(startDate);
             while (cursor <= now) {
                const nav = getNAV(history, cursor, 'PURCHASE');
                if (nav) units += inv.amount / nav;
                cashFlows.push({ date: new Date(cursor), amount: -inv.amount });
                invested += inv.amount;
                cursor.setMonth(cursor.getMonth() + 1);
             }
        }

        const currentNav = parseFloat(history[0].nav); // Latest
        const currentValue = units * currentNav;
        const xirr = calculateXIRR(cashFlows, currentValue, new Date());

        const volatility = calculateVolatility(history, startDate);

        let beta = 0;
        let alpha = 0;

        if (benchmarkHistory && benchmarkHistory.length > 0) {
             beta = calculateBeta(history, benchmarkHistory, startDate);
             // Simple Jensen's Alpha: Alpha = R_fund - (Rf + Beta * (R_bench - Rf))
             // Using 6% as Risk Free Rate

             // Let's get benchmark returns over the period
             const bStartNav = getNAV(benchmarkHistory, startDate, 'PURCHASE') || 10;
             const bEndNav = parseFloat(benchmarkHistory[0].nav);
             const years = (now.getTime() - startDate.getTime()) / (1000 * 3600 * 24 * 365);
             const rm = Math.pow(bEndNav / bStartNav, 1/Math.max(years, 0.1)) - 1;

             const rf = 0.06;
             alpha = (xirr/100) - (rf + beta * (rm - rf));
             alpha = alpha * 100;
        }

        return {
            name: inv.name,
            invested,
            currentValue,
            xirr,
            volatility,
            beta,
            alpha
        };
    }).filter(f => f !== null) as any[];

    // Recalculate Portfolio Aggregates separately (using the same logic as the new helper)
    // We can reuse the result from generateBacktestData passing through calculatePortfolioStats
    // But for this function's return signature, we'll do a quick sum or return formatted data

    // NOTE: This function `calculateFundRatios` is used by the AnalysisDashboard. 
    // We will align its return type to be consistent.

    const totalInvested = funds.reduce((acc, f) => acc + f.invested, 0);
    const totalValue = funds.reduce((acc, f) => acc + f.currentValue, 0);

    // Weighted averages for portfolio ratios (Approximation)
    const weightedXirr = funds.reduce((acc, f) => acc + (f.xirr * (f.currentValue/totalValue)), 0);
    const weightedVol = funds.reduce((acc, f) => acc + (f.volatility * (f.currentValue/totalValue)), 0);
    const weightedBeta = funds.reduce((acc, f) => acc + (f.beta * (f.currentValue/totalValue)), 0);
    const weightedAlpha = funds.reduce((acc, f) => acc + (f.alpha * (f.currentValue/totalValue)), 0);

    return {
        funds,
        portfolio: {
            invested: totalInvested,
            currentValue: totalValue,
            xirr: weightedXirr,
            volatility: weightedVol,
            beta: weightedBeta,
            alpha: weightedAlpha
        }
    };
};

