// Newton-Raphson method to calculate XIRR
export const calculateXIRR = (transactions: CashFlow[], currentValue: number, valuationDate: Date): number => {
  const flows = [...transactions, { date: valuationDate, amount: currentValue }];

  if (flows.length < 2) return 0;

  // Initial guess (10%)
  let rate = 0.1; 

  for (let i = 0; i < 50; i++) { // Max 50 iterations
    let fValue = 0;
    let fDerivative = 0;

    for (const flow of flows) {
      const days = (flow.date.getTime() - flows[0].date.getTime()) / (1000 * 60 * 60 * 24);
      const years = days / 365;

      const r = Math.max(rate, -0.99); 

      const pvFactor = Math.pow(1 + r, years);
      fValue += flow.amount / pvFactor;
      fDerivative -= (years * flow.amount) / (pvFactor * (1 + r));
    }

    if (Math.abs(fValue) < 1) break; // Precision threshold

    const newRate = rate - fValue / fDerivative;
    if (isNaN(newRate) || !isFinite(newRate)) return 0; 
    rate = newRate;
  }

  return rate * 100; // Return percentage
};

// Calculate Max Drawdown from a series of values
const calculateMaxDrawdown = (values: number[]): number => {
    if (values.length === 0) return 0;

    let maxPeak = values[0];
    let maxDrawdown = 0;

    for (const v of values) {
        if (v > maxPeak) {
            maxPeak = v;
        }
        const drawdown = (maxPeak - v) / maxPeak;
        if (drawdown > maxDrawdown) {
            maxDrawdown = drawdown;
        }
    }

    return maxDrawdown * 100; // percentage
};

// Calculate Volatility (Annualized Standard Deviation of Returns)
const calculateVolatility = (navHistory: NAVData[], startDate: Date): number => {
    const history = navHistory
        .map(h => ({ date: parseAPIDate(h.date), nav: parseFloat(h.nav) }))
        .filter(h => h.date >= startDate)
        .sort((a, b) => a.date.getTime() - b.date.getTime()); 

    if (history.length < 30) return 0;

    const returns = [];
    for (let i = 1; i < history.length; i++) {
        const r = (history[i].nav - history[i - 1].nav) / history[i - 1].nav;
        returns.push(r);
    }

    const mean = returns.reduce((a, b) => a + b, 0) / returns.length;
    const variance = returns.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / returns.length;

    return Math.sqrt(variance) * Math.sqrt(252) * 100;
};

// Calculate Beta (Covariance / Variance)
const calculateBeta = (assetHistory: NAVData[], benchmarkHistory: NAVData[], startDate: Date): number => {
    const assetMap = new Map<string, number>();
    assetHistory.forEach(h => assetMap.set(h.date, parseFloat(h.nav)));

    // Normalize dates
    const commonDates = benchmarkHistory
        .filter(h => parseAPIDate(h.date) >= startDate && assetMap.has(h.date))
        .map(h => h.date)
        .reverse(); // Ensure Ascending order

    if (commonDates.length < 30) return 1; 

    const assetReturns: number[] = [];
    const benchReturns: number[] = [];

    // Helper to get closest previous date NAV if direct date match missing in sorted arrays
    // For simplicity here we rely on exact date match from API which works for EOD data usually

    for (let i = 1; i < commonDates.length; i++) {
        const currDate = commonDates[i];
        const prevDate = commonDates[i-1];

        const assetCurr = assetMap.get(currDate)!;
        const assetPrev = assetMap.get(prevDate)!;

        const benchCurr = parseFloat(benchmarkHistory.find(h => h.date === currDate)!.nav);
        const benchPrev = parseFloat(benchmarkHistory.find(h => h.date === prevDate)!.nav);

        assetReturns.push((assetCurr - assetPrev) / assetPrev);
        benchReturns.push((benchCurr - benchPrev) / benchPrev);
    }

    const meanAsset = assetReturns.reduce((a, b) => a + b, 0) / assetReturns.length;
    const meanBench = benchReturns.reduce((a, b) => a + b, 0) / benchReturns.length;

    let covariance = 0;
    let varianceBench = 0;

    for (let i = 0; i < assetReturns.length; i++) {
        covariance += (assetReturns[i] - meanAsset) * (benchReturns[i] - meanBench);
        varianceBench += Math.pow(benchReturns[i] - meanBench, 2);
    }

    if (varianceBench === 0) return 1;
    return covariance / varianceBench;
};

// --- NEW CONSOLIDATED CALCULATOR ---

export const calculatePortfolioStats = (
    investments: Investment[],
    chartData: ChartDataPoint[],
    benchmarkHistory?: NAVData[]
): PortfolioMetrics => {
    // Basic Sums
    let totalInvested = 0;
    let currentValueDirect = 0;
    let currentValueRegular = 0;
    const cashFlows: CashFlow[] = [];

    // Calculate aggregated cashflows for XIRR
    // Note: We need accurate daily cashflows for XIRR. 
    // Re-simulating simply to get cashflow array

    investments.forEach(inv => {
        const startDate = parseISODate(inv.startDate);
        const endDate = inv.endDate ? parseISODate(inv.endDate) : null;
        const now = new Date();

        // Simulating SIPs/Lumpsum to get cashflows
        if (inv.type === InvestmentType.LUMPSUM) {
             totalInvested += inv.amount;
             cashFlows.push({ date: startDate, amount: -inv.amount });
        } else {
             // SIP
             let cursor = new Date(startDate);
             while (cursor <= now) {
                if (endDate && cursor > endDate) break;

                totalInvested += inv.amount;
                cashFlows.push({ date: new Date(cursor), amount: -inv.amount });
                cursor.setMonth(cursor.getMonth() + 1);
             }
        }
    });

    // Get current values from last chart data point
    if (chartData.length > 0) {
        const last = chartData[chartData.length - 1];
        currentValueDirect = last.directValue;
        currentValueRegular = last.regularValue;
    }

    // XIRR
    const xirr = calculateXIRR(cashFlows, currentValueDirect, new Date());

    // Absolute Return
    const absoluteReturn = totalInvested > 0 
        ? ((currentValueDirect - totalInvested) / totalInvested) * 100 
        : 0;

    // Max Drawdown (using Chart Data Portfolio Value curve)
    // We use the directValue curve
    const portfolioValues = chartData.map(d => d.directValue);
    const maxDrawdown = calculateMaxDrawdown(portfolioValues);

    // RoMaD (Return on Max Drawdown)
    // Using XIRR / MaxDrawdown. (If MaxDD is 0, RoMaD is infinite/capped)
    // Since MaxDrawdown is a risk, a lower number is better. 
    // RoMaD = Return / Risk.
    const romad = maxDrawdown > 0 ? xirr / maxDrawdown : (xirr > 0 ? 100 : 0); 

    // Alpha & Beta (If Benchmark exists)
    let alpha = 0;
    let beta = 0;

    if (benchmarkHistory && benchmarkHistory.length > 0 && chartData.length > 6) {
        // Calculate Portfolio Beta roughly using the monthly data points
        // CRITICAL: We must adjust for cashflows (SIPs) to get the true "Investment Return" for the period

        const portfolioReturns = [];
        const benchmarkReturns = [];

        for (let i = 1; i < chartData.length; i++) {
             const prev = chartData[i-1];
             const curr = chartData[i];

             // Calculate Net Flow for the month (New Investment)
             const cashflow = curr.investedAmount - prev.investedAmount;

             if(prev.directValue > 0 && prev.benchmarkValue !== undefined && curr.benchmarkValue !== undefined) {
                 // Return = (EndValue - StartValue - NetFlow) / (StartValue + NetFlow)
                 // Denominator assumes cashflow contributes to the base. 

                 const pDenom = prev.directValue + cashflow;
                 const pRet = pDenom > 0 ? (curr.directValue - prev.directValue - cashflow) / pDenom : 0;

                 const bDenom = prev.benchmarkValue + cashflow;
                 const bRet = bDenom > 0 ? (curr.benchmarkValue - prev.benchmarkValue - cashflow) / bDenom : 0;

                 portfolioReturns.push(pRet);
                 benchmarkReturns.push(bRet);
             }
        }

        if (portfolioReturns.length > 0) {
            const meanPort = portfolioReturns.reduce((a,b) => a+b, 0) / portfolioReturns.length;
            const meanBench = benchmarkReturns.reduce((a,b) => a+b, 0) / benchmarkReturns.length;

            let cov = 0;
            let varBench = 0;
            for(let i=0; i<portfolioReturns.length; i++) {
                cov += (portfolioReturns[i] - meanPort) * (benchmarkReturns[i] - meanBench);
                varBench += Math.pow(benchmarkReturns[i] - meanBench, 2);
            }

            beta = varBench > 0 ? cov / varBench : 1;

            // Jensen's Alpha (Annualized)
            // Alpha = Rp - (Rf + Beta * (Rm - Rf))
            // Assuming Rf (Risk Free) = 6%
            const rf = 0.06;

            // For Rm (Market Return), we use the CAGR of the Benchmark Simulation over the period
            // Rm_annual ~ (1 + meanBench)^12 - 1
            const rm = Math.pow(1 + meanBench, 12) - 1;

            // Using XIRR for Rp is more accurate than mean monthly return for the portfolio
            const rp = xirr / 100;

            alpha = rp - (rf + beta * (rm - rf));
            alpha = alpha * 100; // to percentage
        }
    }

    return {
        totalInvested,
        currentValue: currentValueDirect,
        regularValue: currentValueRegular,
        xirr,
        absoluteReturn,
        maxDrawdown,
        romad,
        alpha: benchmarkHistory ? alpha : undefined,
        beta: benchmarkHistory ? beta : undefined
    };
};

// Existing fund-level calculator for the dashboard table
export const calculateFundRatios = (investments: Investment[], benchmarkHistory: NAVData[]) => {
    // Calculate for individual funds
    const funds = investments.map(inv => {
        const history = inv.isDirect ? inv.navHistory : inv.counterpartNavHistory;
        if (!history || history.length === 0) return null;

        const startDate = parseISODate(inv.startDate);
        const endDate = inv.endDate ? parseISODate(inv.endDate) : null;
        const cashFlows: CashFlow[] = [];
        let units = 0;
        let invested = 0;
        const now = new Date();

        if (inv.type === InvestmentType.LUMPSUM) {
             const nav = getNAV(history, startDate, 'PURCHASE');
             if (nav) units += inv.amount / nav;
             cashFlows.push({ date: startDate, amount: -inv.amount });
             invested += inv.amount;
        } else {
             let cursor = new Date(startDate);
             while (cursor <= now) {
                if (endDate && cursor > endDate) break;

                const nav = getNAV(history, cursor, 'PURCHASE');
                if (nav) units += inv.amount / nav;
                cashFlows.push({ date: new Date(cursor), amount: -inv.amount });
                invested += inv.amount;
                cursor.setMonth(cursor.getMonth() + 1);
             }
        }

        const currentNav = parseFloat(history[0].nav); // Latest
        const currentValue = units * currentNav;
        const xirr = calculateXIRR(cashFlows, currentValue, new Date());

        const volatility = calculateVolatility(history, startDate);

        let beta = 0;
        let alpha = 0;

        if (benchmarkHistory && benchmarkHistory.length > 0) {
             beta = calculateBeta(history, benchmarkHistory, startDate);
             // Simple Jensen's Alpha: Alpha = R_fund - (Rf + Beta * (R_bench - Rf))
             // Using 6% as Risk Free Rate

             // Let's get benchmark returns over the period
             const bStartNav = getNAV(benchmarkHistory, startDate, 'PURCHASE') || 10;
             const bEndNav = parseFloat(benchmarkHistory[0].nav);
             const years = (now.getTime() - startDate.getTime()) / (1000 * 3600 * 24 * 365);
             const rm = Math.pow(bEndNav / bStartNav, 1/Math.max(years, 0.1)) - 1;

             const rf = 0.06;
             alpha = (xirr/100) - (rf + beta * (rm - rf));
             alpha = alpha * 100;
        }

        return {
            name: inv.name,
            invested,
            currentValue,
            xirr,
            volatility,
            beta,
            alpha
        };
    }).filter(f => f !== null) as any[];

    // Recalculate Portfolio Aggregates separately (using the same logic as the new helper)
    // We can reuse the result from generateBacktestData passing through calculatePortfolioStats
    // But for this function's return signature, we'll do a quick sum or return formatted data

    // NOTE: This function `calculateFundRatios` is used by the AnalysisDashboard. 
    // We will align its return type to be consistent.

    const totalInvested = funds.reduce((acc, f) => acc + f.invested, 0);
    const totalValue = funds.reduce((acc, f) => acc + f.currentValue, 0);

    // Weighted averages for portfolio ratios (Approximation)
    const weightedXirr = funds.reduce((acc, f) => acc + (f.xirr * (f.currentValue/totalValue)), 0);
    const weightedVol = funds.reduce((acc, f) => acc + (f.volatility * (f.currentValue/totalValue)), 0);
    const weightedBeta = funds.reduce((acc, f) => acc + (f.beta * (f.currentValue/totalValue)), 0);
    const weightedAlpha = funds.reduce((acc, f) => acc + (f.alpha * (f.currentValue/totalValue)), 0);

    return {
        funds,
        portfolio: {
            invested: totalInvested,
            currentValue: totalValue,
            xirr: weightedXirr,
            volatility: weightedVol,
            beta: weightedBeta,
            alpha: weightedAlpha
        }
    };
};

import React, { useState, useEffect, useRef } from 'react';
import { InvestmentType } from '../types';
import { PlusCircle, Search, Loader2, ArrowRightLeft, Edit2, Check, X, ChevronRight } from 'lucide-react';
import { searchMF, MFScheme, findCounterpartScheme, isDirectPlan } from '../services/mfApiService';

interface AddInvestmentFormProps {
  onAdd: (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string,
    endDate?: string
  ) => void;
  isProcessing: boolean;
}

export const AddInvestmentForm: React.FC<AddInvestmentFormProps> = ({ onAdd, isProcessing }) => {
  const [step, setStep] = useState<'SEARCH' | 'CONFIGURE'>('SEARCH');

  const [query, setQuery] = useState('');
  const [results, setResults] = useState<MFScheme[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  const [directScheme, setDirectScheme] = useState<MFScheme | null>(null);
  const [regularScheme, setRegularScheme] = useState<MFScheme | null>(null);
  const [investedIn, setInvestedIn] = useState<'DIRECT' | 'REGULAR'>('REGULAR');

  const [editingSlot, setEditingSlot] = useState<'DIRECT' | 'REGULAR' | null>(null);

  const [type, setType] = useState<InvestmentType>(InvestmentType.SIP);
  const [amount, setAmount] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  const searchTimeout = useRef<NodeJS.Timeout>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const resetForm = () => {
    setStep('SEARCH');
    setQuery('');
    setResults([]);
    setDirectScheme(null);
    setRegularScheme(null);
    setAmount('');
    setStartDate('');
    setEndDate('');
    setEditingSlot(null);
  };

  useEffect(() => {
    if (query.length < 3) {
      setResults([]);
      return;
    }

    if (searchTimeout.current) clearTimeout(searchTimeout.current);

    setIsSearching(true);
    searchTimeout.current = setTimeout(async () => {
      const data = await searchMF(query);
      setResults(data.slice(0, 10));
      setIsSearching(false);
    }, 500);

    return () => {
      if (searchTimeout.current) clearTimeout(searchTimeout.current);
    };
  }, [query]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setResults([]);
        if (editingSlot) {
            setEditingSlot(null);
            setQuery(''); 
        }
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [editingSlot]);

  const handleInitialSelect = async (scheme: MFScheme) => {
    setQuery('');
    setResults([]);

    const isDirect = isDirectPlan(scheme.schemeName);

    let dScheme: MFScheme | null = isDirect ? scheme : null;
    let rScheme: MFScheme | null = !isDirect ? scheme : null;

    setInvestedIn(isDirect ? 'DIRECT' : 'REGULAR');

    try {
      const counterpart = await findCounterpartScheme(scheme.schemeCode, scheme.schemeName);
      if (counterpart) {
        if (isDirect) rScheme = counterpart;
        else dScheme = counterpart;
      }
    } catch (e) {
      console.error("Auto-match failed", e);
    }

    setDirectScheme(dScheme);
    setRegularScheme(rScheme);
    setStep('CONFIGURE');
  };

  const handleSlotSelect = (scheme: MFScheme) => {
    if (editingSlot === 'DIRECT') setDirectScheme(scheme);
    if (editingSlot === 'REGULAR') setRegularScheme(scheme);

    setEditingSlot(null);
    setQuery('');
    setResults([]);
  };

  const startEditingSlot = (slot: 'DIRECT' | 'REGULAR') => {
    setEditingSlot(slot);
    setQuery(''); 
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const investedScheme = investedIn === 'DIRECT' ? directScheme : regularScheme;
    const counterpartScheme = investedIn === 'DIRECT' ? regularScheme : directScheme;

    if (!investedScheme || !amount || !startDate) return;

    // Basic validation
    if (endDate && startDate > endDate) {
        alert("End date must be after start date");
        return;
    }

    onAdd(investedScheme, counterpartScheme, type, parseFloat(amount), startDate, endDate || undefined);
    resetForm();
  };

  const renderSchemeCard = (label: string, scheme: MFScheme | null, slot: 'DIRECT' | 'REGULAR') => {
    const isSelected = investedIn === slot;
    const isEditing = editingSlot === slot;

    if (isEditing) {
       return (
         <div className="relative p-1" ref={dropdownRef}>
            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Search {label}</label>
            <div className="relative">
                <input
                    autoFocus
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder={`Search ${label}...`}
                    className="w-full rounded-md border-emerald-500 border-2 px-3 py-2 text-sm outline-none shadow-sm"
                />
                 <button 
                    type="button"
                    onClick={() => setEditingSlot(null)}
                    className="absolute right-2 top-2 text-slate-400 hover:text-slate-600"
                >
                    <X size={16} />
                </button>
            </div>
            {results.length > 0 && (
                <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-lg shadow-xl mt-1 max-h-48 overflow-y-auto z-50">
                    {results.map((s) => (
                        <div
                            key={s.schemeCode}
                            onClick={() => handleSlotSelect(s)}
                            className="px-3 py-2 hover:bg-emerald-50 cursor-pointer text-xs text-slate-700 border-b border-slate-50"
                        >
                            {s.schemeName}
                        </div>
                    ))}
                </div>
            )}
         </div>
       )
    }

    return (
      <div 
        className={`p-4 rounded-xl border-2 transition-all relative group cursor-pointer ${
          isSelected 
          ? 'border-emerald-500 bg-emerald-50/30' 
          : 'border-slate-200 bg-white hover:border-emerald-200'
        }`}
        onClick={() => setInvestedIn(slot)}
      >
        <div className="flex justify-between items-start gap-2">
            <div className="flex-1">
                <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-bold uppercase tracking-wider px-1.5 py-0.5 rounded ${isSelected ? 'bg-emerald-100 text-emerald-800' : 'bg-slate-100 text-slate-500'}`}>
                        {label}
                    </span>
                    {isSelected && <span className="text-[10px] text-emerald-600 font-medium flex items-center"><Check size={10} className="mr-0.5"/> Selected</span>}
                </div>
                {scheme ? (
                    <p className={`text-sm font-semibold leading-tight line-clamp-2 ${isSelected ? 'text-slate-900' : 'text-slate-600'}`}>
                        {scheme.schemeName}
                    </p>
                ) : (
                    <p className="text-sm italic text-amber-600/80">Select plan manually</p>
                )}
            </div>
        </div>

        <button 
            type="button"
            onClick={(e) => {
                e.stopPropagation();
                startEditingSlot(slot);
            }}
            className="absolute top-2 right-2 p-1.5 text-slate-300 hover:text-blue-600 hover:bg-blue-50 rounded-full opacity-0 group-hover:opacity-100 transition-all"
            title="Change Fund"
        >
            <Edit2 size={12} />
        </button>
      </div>
    );
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative z-20 h-full">
      <div className="flex items-center gap-3 mb-6 border-b border-slate-100 pb-4">
        <div className="bg-emerald-100 p-2 rounded-lg text-emerald-700">
            {step === 'SEARCH' ? <Search size={20} /> : <PlusCircle size={20} />}
        </div>
        <div>
            <h2 className="text-lg font-bold text-slate-900 leading-none">
                {step === 'SEARCH' ? 'Find Fund' : 'Configure Investment'}
            </h2>
            <p className="text-xs text-slate-400 mt-1">
                {step === 'SEARCH' ? 'Search AMFI database' : 'Set parameters for backtest'}
            </p>
        </div>
      </div>

      {step === 'SEARCH' ? (
        <div className="relative pb-8" ref={dropdownRef}>
          <div className="relative group">
             <div className="absolute inset-y-0 left-0 pl-3.5 flex items-center pointer-events-none">
                {isSearching ? <Loader2 className="h-5 w-5 text-emerald-500 animate-spin" /> : <Search className="h-5 w-5 text-slate-400 group-focus-within:text-emerald-500 transition-colors" />}
             </div>
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="E.g. HDFC Midcap Opportunities..."
              className="pl-11 w-full rounded-xl border-slate-200 border-2 px-4 py-3.5 text-sm focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 outline-none transition-all shadow-sm"
              autoFocus
            />
          </div>

          {results.length > 0 && (
            <div className="absolute top-full left-0 right-0 bg-white border border-slate-200 rounded-xl shadow-2xl mt-2 max-h-72 overflow-y-auto z-50 divide-y divide-slate-50">
              {results.map((scheme) => (
                <div
                  key={scheme.schemeCode}
                  onClick={() => handleInitialSelect(scheme)}
                  className="px-4 py-3 hover:bg-emerald-50 cursor-pointer group flex items-center justify-between"
                >
                  <div>
                    <p className="text-sm font-medium text-slate-700 group-hover:text-emerald-900">{scheme.schemeName}</p>
                    <p className="text-[10px] text-slate-400 mt-0.5">Code: {scheme.schemeCode}</p>
                  </div>
                  <ChevronRight size={16} className="text-slate-300 group-hover:text-emerald-500" />
                </div>
              ))}
            </div>
          )}
        </div>
      ) : (
        <form onSubmit={handleSubmit} className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">

           <div className="space-y-3">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">Select Plan to Invest In</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3 relative">
                  {renderSchemeCard('DIRECT', directScheme, 'DIRECT')}
                  {renderSchemeCard('REGULAR', regularScheme, 'REGULAR')}
