                    </>
                ) : (
                    'Add to Portfolio'
                )}
                </button>
           </div>
        </form>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { Investment, InvestmentType } from '../types';
import { Trash2, Loader2, TrendingUp, AlertTriangle, CheckCircle2, Edit2, Check, X, Calendar, IndianRupee, ArrowRight } from 'lucide-react';

interface InvestmentListProps {
  investments: Investment[];
  onRemove: (id: string) => void;
  onUpdate: (id: string, amount: number, startDate: string, endDate?: string) => void;
  selectedId: string | null;
  onSelect: (id: string) => void;
}

export const InvestmentList: React.FC<InvestmentListProps> = ({ investments, onRemove, onUpdate, selectedId, onSelect }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValues, setEditValues] = useState<{amount: string, startDate: string, endDate: string}>({ amount: '', startDate: '', endDate: '' });

  const handleEditClick = (e: React.MouseEvent, inv: Investment) => {
    e.stopPropagation();
    setEditingId(inv.id);
    setEditValues({ 
        amount: inv.amount.toString(), 
        startDate: inv.startDate,
        endDate: inv.endDate || ''
    });
  };

  const handleCancel = (e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingId(null);
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (editingId && editValues.amount && editValues.startDate) {
        if (editValues.endDate && editValues.startDate > editValues.endDate) {
            alert("End date must be after start date");
            return;
        }
      onUpdate(editingId, parseFloat(editValues.amount), editValues.startDate, editValues.endDate || undefined);
      setEditingId(null);
    }
  };

  const handleRemove = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    onRemove(id);
  };

  const handleCardClick = (id: string) => {
    // Only allow selection if not editing
    if (!editingId) {
        onSelect(id);
    }
  };

  if (investments.length === 0) {
    return (
      <div className="text-center py-16 bg-white rounded-2xl border border-dashed border-slate-300 shadow-sm">
        <div className="mx-auto h-16 w-16 text-slate-300 flex items-center justify-center rounded-full bg-slate-50 mb-4">
          <TrendingUp size={32} />
        </div>
        <h3 className="text-lg font-semibold text-slate-900">No investments added</h3>
        <p className="mt-2 text-slate-500 max-w-sm mx-auto">
          Start by adding a mutual fund using the configuration panel above to analyze your portfolio.
        </p>
      </div>
    );
  }

  return (
    <div className="grid gap-6 grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
      {investments.map((inv) => {
        const isEditing = editingId === inv.id;
        const isSelected = selectedId === inv.id;

        return (
          <div 
            key={inv.id} 
            onClick={() => handleCardClick(inv.id)}
            className={`
                group relative bg-white rounded-2xl transition-all duration-300 p-5 cursor-pointer
                ${isEditing 
                    ? 'border-2 border-emerald-500 shadow-lg scale-[1.02] z-10' 
                    : isSelected 
                        ? 'border-2 border-emerald-500 shadow-md ring-4 ring-emerald-50/50' 
                        : 'border border-slate-200 hover:shadow-xl hover:border-emerald-200 hover:-translate-y-1'
                }
            `}
          >
            <div className="flex justify-between items-start mb-4">
              <div className="flex-1 pr-3">
                 <span className={`inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide mb-2 ${inv.isDirect ? 'bg-emerald-50 text-emerald-700' : 'bg-blue-50 text-blue-700'}`}>
                    {inv.isDirect ? 'Direct' : 'Regular'} Plan
                 </span>
                <h4 className="font-bold text-slate-900 line-clamp-2 leading-tight h-[2.5em]" title={inv.name}>
                  {inv.name}
                </h4>
              </div>

              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-4 right-4 bg-white/90 backdrop-blur-sm p-1 rounded-lg shadow-sm border border-slate-100">
                {isEditing ? (
                  <>
                    <button 
                      onClick={(e) => handleSave(e)}
                      className="text-white bg-emerald-500 hover:bg-emerald-600 p-1.5 rounded-md transition-colors shadow-sm"
                      title="Save"
                    >
                      <Check size={14} />
                    </button>
                    <button 
                      onClick={(e) => handleCancel(e)}
                      className="text-slate-500 hover:bg-slate-100 p-1.5 rounded-md transition-colors"
                      title="Cancel"
                    >
                      <X size={14} />
                    </button>
                  </>
                ) : (
                  <>
                    <button 
                      onClick={(e) => handleEditClick(e, inv)}
                      className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 p-1.5 rounded-md transition-colors"
                      title="Edit"
                    >
                      <Edit2 size={14} />
                    </button>
                    <button 
                      onClick={(e) => handleRemove(e, inv.id)}
                      className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-1.5 rounded-md transition-colors"
                      title="Delete"
                    >
                      <Trash2 size={14} />
                    </button>
                  </>
                )}
              </div>
            </div>

            <div className="space-y-4">
              {isEditing ? (
                <div className="space-y-3 bg-slate-50 p-4 rounded-xl border border-slate-100 shadow-inner" onClick={(e) => e.stopPropagation()}>
                   <div className="space-y-1.5">
                      <label className="text-xs font-semibold text-slate-500 block">Amount</label>
                      <div className="relative">
                        <IndianRupee size={12} className="absolute left-2.5 top-2.5 text-slate-400"/>
                        <input 
                            type="number" 
                            value={editValues.amount}
                            onChange={(e) => setEditValues({...editValues, amount: e.target.value})}
                            className="w-full text-sm pl-7 pr-2 py-1.5 border border-slate-200 rounded-lg focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none"
                        />
                      </div>
                   </div>
                   <div className="grid grid-cols-2 gap-2">
                        <div className="space-y-1.5">
                            <label className="text-xs font-semibold text-slate-500 block">Start</label>
                            <input 
                                type="date" 
                                value={editValues.startDate}
                                onChange={(e) => setEditValues({...editValues, startDate: e.target.value})}
                                className="w-full text-sm px-2 py-1.5 border border-slate-200 rounded-lg focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none"
                            />
                        </div>
                        {inv.type === InvestmentType.SIP && (
                            <div className="space-y-1.5">
                                <label className="text-xs font-semibold text-slate-500 block">End</label>
                                <input 
                                    type="date" 
                                    value={editValues.endDate}
                                    onChange={(e) => setEditValues({...editValues, endDate: e.target.value})}
                                    className="w-full text-sm px-2 py-1.5 border border-slate-200 rounded-lg focus:border-emerald-500 focus:ring-2 focus:ring-emerald-500/20 outline-none"
                                />
                            </div>
                        )}
                   </div>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3">
                  <div className="bg-slate-50 rounded-lg p-2.5 border border-slate-100">
                    <span className="text-[10px] uppercase font-semibold text-slate-400 block mb-0.5">{inv.type}</span>
                    <span className="font-bold text-slate-900 flex items-center gap-1">
                        <IndianRupee size={12} className="text-slate-400"/> {inv.amount.toLocaleString('en-IN')}
                    </span>
                  </div>
                   <div className="bg-slate-50 rounded-lg p-2.5 border border-slate-100">
                    <span className="text-[10px] uppercase font-semibold text-slate-400 block mb-0.5">Duration</span>
                    <span className="font-bold text-slate-900 flex items-center gap-1">
                        <span className="truncate">
                        {new Date(inv.startDate).toLocaleDateString('en-GB', { month: 'short', year: '2-digit' })}
                        {inv.endDate ? (
                            <>
                             <ArrowRight size={10} className="inline mx-1 text-slate-400" />
                             {new Date(inv.endDate).toLocaleDateString('en-GB', { month: 'short', year: '2-digit' })}
                            </>
                        ) : (
                             inv.type === InvestmentType.SIP ? <span className="text-emerald-600 text-[10px] ml-1 uppercase">Ongoing</span> : null
                        )}
                        </span>
                    </span>
                  </div>
                </div>
              )}

              <div className="pt-3 border-t border-slate-100">
                 {inv.isLoading ? (
                  <div className="flex items-center text-emerald-600 text-xs font-medium bg-emerald-50 px-3 py-2 rounded-lg">
                    <Loader2 className="animate-spin mr-2 h-3 w-3" />
                    Fetching NAV history...
                  </div>
                ) : (
                  <div className="space-y-2">
                    {inv.counterpartSchemeCode ? (
                          <div className="flex items-center text-slate-500 text-xs bg-slate-50 px-2 py-1.5 rounded-md border border-slate-100">
                              <CheckCircle2 className="w-3.5 h-3.5 mr-1.5 text-emerald-500 flex-shrink-0" />
                              <span className="truncate">Comparing vs {inv.isDirect ? 'Regular' : 'Direct'}</span>
                          </div>
                      ) : (
                          <div className="flex items-center text-amber-600 text-xs bg-amber-50 px-2 py-1.5 rounded-md border border-amber-100">
                              <AlertTriangle className="w-3.5 h-3.5 mr-1.5 flex-shrink-0" />
                              Comparison Unavailable
                          </div>
                      )}

                    {inv.error && (
                      <div className="text-xs text-red-500 bg-red-50 px-2 py-1 rounded-md border border-red-100">
                          {inv.error}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>

            {/* Selection Indicator */}
            {isSelected && (
                <div className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-500 rounded-full border-2 border-white"></div>
            )}
          </div>
        );
      })}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Layout } from './components/Layout';
import { AddInvestmentForm } from './components/AddInvestmentForm';
import { InvestmentList } from './components/InvestmentList';
import { ComparisonChart } from './components/ComparisonChart';
import { BenchmarkSelector } from './components/BenchmarkSelector';
import { AnalysisDashboard } from './components/AnalysisDashboard';
import { Investment, InvestmentType, NAVData } from './types';
import { getMFData, isDirectPlan, MFScheme } from './services/mfApiService';
import { generateBacktestData, formatCurrency, calculatePortfolioStats } from './utils/financials';
import { Info, FilterX, AlertCircle, BarChart3, PieChart, Download, Upload, TrendingUp, DollarSign, Wallet, TrendingDown, Activity, ShieldCheck } from 'lucide-react';

const App: React.FC = () => {
  const [investments, setInvestments] = useState<Investment[]>([]);
  const [selectedInvestmentId, setSelectedInvestmentId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'CHART' | 'RATIOS'>('CHART');

  // Benchmark State
  const [benchmarkScheme, setBenchmarkScheme] = useState<MFScheme | null>(null);
  const [benchmarkHistory, setBenchmarkHistory] = useState<NAVData[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('mf_portfolio_v2');
    if (saved) {
      try {
        setInvestments(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse saved portfolio");
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('mf_portfolio_v2', JSON.stringify(investments));
  }, [investments]);

  // Handle Benchmark Changes
  const handleBenchmarkSelect = async (scheme: MFScheme | null) => {
      setBenchmarkScheme(scheme);
      if (scheme) {
          try {
              const data = await getMFData(scheme.schemeCode);
              if (data) {
                  setBenchmarkHistory(data.data);
              }
          } catch (e) {
              console.error("Failed to fetch benchmark", e);
          }
      } else {
          setBenchmarkHistory([]);
      }
  };

  const handleExportPortfolio = () => {
    const dataStr = JSON.stringify(investments, null, 2);
    const blob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `mf-portfolio-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        const parsedData = JSON.parse(content);
        if (Array.isArray(parsedData)) {
            const isValid = parsedData.every(item => item.id && item.schemeCode && item.amount);
            if (isValid) {
                setInvestments(parsedData);
            } else {
                alert("Invalid portfolio file format.");
            }
        }
      } catch (error) {
        console.error("Error parsing file", error);
        alert("Failed to read portfolio file.");
      }
    };
    reader.readAsText(file);
    event.target.value = ''; // Reset
  };

  const handleAddInvestment = async (
    investedScheme: MFScheme, 
    counterpartScheme: MFScheme | null, 
    type: InvestmentType, 
    amount: number, 
    startDate: string,
    endDate?: string
  ) => {
    const isDirect = isDirectPlan(investedScheme.schemeName);

    // Create initial entry
    const newInvestment: Investment = {
      id: uuidv4(),
      schemeCode: investedScheme.schemeCode,
      name: investedScheme.schemeName,
      isDirect,
      type,
      amount,
      startDate,
      endDate,
      navHistory: [],
      counterpartSchemeCode: counterpartScheme?.schemeCode,
      counterpartName: counterpartScheme?.schemeName,
      isLoading: true
    };

    setInvestments(prev => [...prev, newInvestment]);
    setIsProcessing(true);

    try {
      const mainData = await getMFData(investedScheme.schemeCode);
      if (!mainData) throw new Error("Could not fetch NAV data for selected fund");

      let counterpartData = null;
      if (counterpartScheme) {
        counterpartData = await getMFData(counterpartScheme.schemeCode);
      }

      setInvestments(prev => prev.map(inv => {
        if (inv.id === newInvestment.id) {
            return {
                ...inv,
                isLoading: false,
                category: mainData.meta.scheme_category,
                fundHouse: mainData.meta.fund_house,
                navHistory: mainData.data,
                counterpartNavHistory: counterpartData?.data || [],
                error: !counterpartData ? "Comparison data unavailable" : undefined
            };
        }
        return inv;
      }));

    } catch (err) {
      console.error(err);
      setInvestments(prev => prev.map(inv => 
        inv.id === newInvestment.id 
          ? { ...inv, isLoading: false, error: "Failed to fetch data." } 
          : inv
      ));
    } finally {
      setIsProcessing(false);
    }
  };

  const removeInvestment = (id: string) => {
    setInvestments(prev => prev.filter(inv => inv.id !== id));
    if (selectedInvestmentId === id) {
      setSelectedInvestmentId(null);
    }
  };

  const updateInvestment = (id: string, amount: number, startDate: string, endDate?: string) => {
    setInvestments(prev => prev.map(inv => 
      inv.id === id 
        ? { ...inv, amount, startDate, endDate }
        : inv
    ));
  };

  const toggleSelection = (id: string) => {
    setSelectedInvestmentId(prev => prev === id ? null : id);
  };

  // Filter data based on selection
  const activeInvestments = useMemo(() => {
    if (selectedInvestmentId) {
      return investments.filter(inv => inv.id === selectedInvestmentId);
    }
    return investments;
  }, [investments, selectedInvestmentId]);

  const chartData = useMemo(() => 
    generateBacktestData(activeInvestments, benchmarkHistory), 
  [activeInvestments, benchmarkHistory]);

  // Extended Stats Calculation
  const stats = useMemo(() => {
      return calculatePortfolioStats(activeInvestments, chartData, benchmarkHistory);
  }, [activeInvestments, chartData, benchmarkHistory]);

  const selectedInvestmentName = useMemo(() => {
    if (!selectedInvestmentId) return 'Entire Portfolio';
    const inv = investments.find(i => i.id === selectedInvestmentId);
    return inv ? inv.name : 'Selected Fund';
  }, [investments, selectedInvestmentId]);

  return (
    <Layout>
      <div className="space-y-12">

        {/* SECTION 1: EXPANDED KPI DASHBOARD (Top Priority) */}
        <section>
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-xl font-bold text-slate-900">Portfolio Performance</h3>
                <div className="flex items-center gap-2">
                    <BenchmarkSelector 
                        selectedScheme={benchmarkScheme} 
                        onSelect={handleBenchmarkSelect} 
                    />
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                {/* CARD 1: VALUE & XIRR */}
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between hover:border-emerald-200 transition-colors">
                    <div>
                        <div className="flex justify-between items-start mb-2">
                            <p className="text-sm text-slate-500 font-medium flex items-center gap-1">
                                <Wallet size={14} /> Total Value
                            </p>
                            <span className="text-xs bg-emerald-50 text-emerald-700 px-2 py-0.5 rounded-full font-bold">
                                {stats.xirr.toFixed(2)}% XIRR
                            </span>
                        </div>
                        <p className="text-3xl font-bold text-slate-900">{formatCurrency(stats.currentValue)}</p>
                    </div>
                    <div className="mt-4 pt-4 border-t border-slate-50 flex justify-between items-center text-xs">
                        <span className="text-slate-400">Invested: {formatCurrency(stats.totalInvested)}</span>
                        <span className="text-emerald-600 font-medium">+{formatCurrency(stats.currentValue - stats.totalInvested)}</span>
                    </div>
                </div>

                {/* CARD 2: OPPORTUNITY COST */}
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between hover:border-emerald-200 transition-colors">
                     <div>
                        <p className="text-sm text-slate-500 font-medium mb-1 flex items-center gap-1">
                            <ShieldCheck size={14} /> Direct Plan Savings
                        </p>
                        <p className="text-3xl font-bold text-emerald-600">
                            {formatCurrency(stats.currentValue - stats.regularValue)}
                        </p>
                    </div>
                     <div className="mt-4 pt-4 border-t border-slate-50 text-xs text-slate-400">
                        Extra wealth created vs Regular plans
                    </div>
                </div>

                {/* CARD 3: RISK METRICS (MaxDD / RoMaD) */}
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm flex flex-col justify-between hover:border-red-200 transition-colors">
                     <div>
                        <div className="flex justify-between items-start mb-2">
                            <p className="text-sm text-slate-500 font-medium flex items-center gap-1">
                                <TrendingDown size={14} /> Max Drawdown
                            </p>
                             <div className="bg-slate-50 text-slate-500 p-1.5 rounded-md">
                                <Activity size={16} />
                            </div>
                        </div>
                        <p className="text-3xl font-bold text-slate-800">
                            -{stats.maxDrawdown.toFixed(2)}%
                        </p>
                    </div>
                     <div className="mt-4 pt-4 border-t border-slate-50 text-xs flex justify-between items-center">
                        <span className="text-slate-400" title="Return on Max Drawdown">RoMaD Score</span>
                        <span className={`font-bold ${stats.romad > 1 ? 'text-emerald-600' : 'text-amber-500'}`}>{stats.romad.toFixed(2)}</span>
                    </div>
                </div>

                {/* CARD 4: ALPHA / BETA */}
                <div className={`bg-white p-6 rounded-2xl border shadow-sm flex flex-col justify-between transition-colors ${benchmarkScheme ? 'border-slate-200 hover:border-violet-200' : 'border-dashed border-slate-300'}`}>
                    {benchmarkScheme ? (
                        <>
                             <div>
                                <div className="flex justify-between items-start mb-2">
                                    <p className="text-sm text-slate-500 font-medium flex items-center gap-1">
                                        <TrendingUp size={14} /> Alpha
                                    </p>
                                    <span className="text-xs text-violet-600 bg-violet-50 px-2 py-0.5 rounded-full font-medium truncate max-w-[100px]">
                                        vs {benchmarkScheme.schemeName}
                                    </span>
                                </div>
                                <p className={`text-3xl font-bold ${stats.alpha! > 0 ? 'text-violet-600' : 'text-slate-600'}`}>
                                    {stats.alpha! > 0 ? '+' : ''}{stats.alpha!.toFixed(2)}%
                                </p>
                            </div>
                            <div className="mt-4 pt-4 border-t border-slate-50 text-xs flex justify-between items-center">
                                <span className="text-slate-400">Beta (Volatility)</span>
                                <span className="font-bold text-slate-700">{stats.beta!.toFixed(2)}</span>
                            </div>
                        </>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-center text-slate-400">
                            <TrendingUp size={32} className="mb-2 opacity-30" />
                            <p className="text-sm font-medium">Add Benchmark</p>
                            <p className="text-xs mt-1 opacity-70">to see Alpha & Beta</p>
                        </div>
                    )}
                </div>
            </div>
        </section>

        {/* SECTION 2: ADD FUNDS */}
        <section>
             <div className="flex items-end justify-between mb-4 border-t border-slate-200 pt-8">
                 <div>
                    <h3 className="text-xl font-bold text-slate-900">Add Investments</h3>
                    <p className="text-sm text-slate-500">Configure your portfolio</p>
                 </div>
                 <div className="hidden md:block text-xs text-slate-400 max-w-md text-right">
                    We automatically find Direct/Regular plan counterparts.
                 </div>
             </div>

             <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-stretch">
                <div className="lg:col-span-8">
                     <AddInvestmentForm onAdd={handleAddInvestment} isProcessing={isProcessing} />
                </div>
                <div className="hidden lg:block lg:col-span-4">
                    <div className="bg-blue-50/50 border border-blue-100 rounded-2xl p-6 h-full flex flex-col justify-center">
                        <div className="mb-4 bg-white w-12 h-12 rounded-xl flex items-center justify-center shadow-sm text-blue-600">
                            <Info size={24} />
                        </div>
                        <h4 className="font-bold text-blue-900 text-lg mb-2">How it works</h4>
                        <p className="text-blue-800/80 text-sm leading-relaxed mb-4">
                            1. <strong>Search</strong> for any fund.<br/>
                            2. We <strong>auto-detect</strong> its counterpart.<br/>
                            3. Set <strong>SIP or Lumpsum</strong>.<br/>
                            4. See <strong>Real Returns</strong> & Risk stats.
                        </p>
                    </div>
                </div>
             </div>
        </section>

        {/* SECTION 3: PORTFOLIO LIST */}
        <section>
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-end border-b border-slate-200 pb-4 mb-6 gap-4 border-t border-slate-200 pt-8">
              <div>
                <h3 className="text-xl font-bold text-slate-900">Your Holdings</h3>
                <p className="text-sm text-slate-500 mt-1">Manage {investments.length} active investments</p>
              </div>
              <div className="flex space-x-2">
                 <input 
                    type="file" 
                    ref={fileInputRef}
                    className="hidden" 
                    accept=".json"
                    onChange={handleFileChange}
                 />
                 <button 
                    onClick={handleImportClick}
