// Helper to check if a name looks like a Direct plan
export const isDirectPlan = (name: string): boolean => {
  return name.toLowerCase().includes('direct');
};

// New Helper: Intelligently find the best Direct Growth match for a raw query
export const findBestMatchingScheme = async (rawQuery: string): Promise<MFScheme | null> => {
  const results = await searchMF(rawQuery);
  if (!results || results.length === 0) return null;

  // We prioritize: Direct Plan AND Growth Option
  // Most users want to backtest the growth option of the direct plan.

  const lowerQuery = rawQuery.toLowerCase();
  const looksLikeIDCW = lowerQuery.includes('idcw') || lowerQuery.includes('dividend');

  // Filter logic
  const bestMatch = results.find(s => {
    const n = s.schemeName.toLowerCase();
    const isDirect = n.includes('direct');
    const isGrowth = n.includes('growth');
    const isIDCW = n.includes('idcw') || n.includes('dividend');

    if (looksLikeIDCW) {
       return isDirect && isIDCW;
    }
    return isDirect && isGrowth;
  });

  // If no perfect match, try just Direct
  if (!bestMatch) {
      return results.find(s => s.schemeName.toLowerCase().includes('direct')) || results[0];
  }

  return bestMatch;
};

// Helper to find the counterpart scheme (Direct <-> Regular)
export const findCounterpartScheme = async (originalCode: string, originalName: string): Promise<MFScheme | null> => {
  const isDirect = isDirectPlan(originalName);

  // 1. Clean up the name to get the 'Core' name
  // Remove "Direct Plan", "Regular Plan", "Direct", "Regular" case insensitive
  let coreName = originalName
    .replace(/Direct Plan/gi, '')
    .replace(/Direct/gi, '')
    .replace(/Regular Plan/gi, '')
    .replace(/Regular/gi, '')
    .trim();

  // Remove common suffixes that might confuse search if strict
  // e.g. "Growth Option" -> "Growth"
  coreName = coreName.replace(/Option/gi, '').trim();

  // Remove hyphens and extra spaces
  coreName = coreName.replace(/-/g, ' ').replace(/\s\s+/g, ' ');

  // Strategy 1: Search for the core name
  let searchResults = await searchMF(coreName);

  // Helper to filter candidates from a result set
  const findMatchInResults = (results: MFScheme[]) => {
      const candidates = results.filter(s => s.schemeCode !== originalCode);
      const lowerName = originalName.toLowerCase();
      const isGrowth = lowerName.includes('growth');
      const isIDCW = lowerName.includes('idcw') || lowerName.includes('dividend');

      return candidates.find(s => {
        const name = s.schemeName.toLowerCase();

        // Must match option type (Growth/IDCW)
        if (isGrowth && !name.includes('growth')) return false;
        if (isIDCW && !name.includes('idcw') && !name.includes('dividend')) return false;

        // Direct vs Regular check
        if (isDirect) {
          // We have Direct, looking for Regular.
          return !name.includes('direct');
        } else {
          // We have Regular, looking for Direct.
          return name.includes('direct');
        }
      });
  };

  let bestMatch = findMatchInResults(searchResults);

  // Strategy 2: If we failed to find the specific counterpart type we need
  if (!bestMatch) {
      // If we have Regular and are looking for Direct, try appending "Direct Plan" to force it
      if (!isDirect) {
          const directSearchResults = await searchMF(`${coreName} Direct Plan`);
          bestMatch = findMatchInResults(directSearchResults);
      } 
      // If we have Direct and are looking for Regular (unlikely to fail on generic, but possible)
      else if (isDirect) {
          // Try searching specifically for Regular (though 'Regular' is often omitted in names)
          // or just search the exact core name again with a more lenient filter if needed?
          // For now, let's try searching "Growth" or "Plan" if the core name is too specific
          // But usually, generic search covers it.
      }
  }

  return bestMatch || null;
};

