  id: string;
  schemeCode: string;
  name: string;
  category?: string;
  fundHouse?: string;

  isDirect: boolean;
  navHistory: NAVData[];

  counterpartSchemeCode?: string;
  counterpartName?: string;
  counterpartNavHistory?: NAVData[];

  type: InvestmentType;
  amount: number;
  startDate: string; // ISO Date string
  endDate?: string; // ISO Date string (Optional)

  tags: string[]; // New field for categorization

