import React, { useState, useMemo } from 'react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { formatCurrency } from '../utils/financials';
import { Calculator, Info, TrendingUp, AlertTriangle } from 'lucide-react';
import { COLORS } from '../constants';

export const ExpenseRatioCalculator: React.FC = () => {
  // Defaults
  const [initialInvestment, setInitialInvestment] = useState(100000); // 1 Lakh
  const [years, setYears] = useState(20);
  const [expectedReturn, setExpectedReturn] = useState(12); // 12% CAGR
  const [directTER, setDirectTER] = useState(0.7);
  const [regularTER, setRegularTER] = useState(2.0);

  const data = useMemo(() => {
    const points = [];
    let currentDirect = initialInvestment;
    let currentRegular = initialInvestment;

    for (let i = 0; i <= years; i++) {
      points.push({
        year: i,
        directValue: Math.round(currentDirect),
        regularValue: Math.round(currentRegular),
        difference: Math.round(currentDirect - currentRegular),
      });

      // Compounding Logic: Effective Rate = (Market Return - TER)
      // Note: This is a simplified annual approximation. Real TER is deducted daily from NAV.
      const directRate = (expectedReturn - directTER) / 100;
      const regularRate = (expectedReturn - regularTER) / 100;

      currentDirect = currentDirect * (1 + directRate);
      currentRegular = currentRegular * (1 + regularRate);
    }
    return points;
  }, [initialInvestment, years, expectedReturn, directTER, regularTER]);

  const finalStats = data[data.length - 1];
  const totalLoss = finalStats.difference;
  const percentageLost = (totalLoss / finalStats.directValue) * 100;

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
      <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center gap-3">
        <div className="bg-orange-100 p-2 rounded-lg text-orange-600">
          <Calculator size={20} />
        </div>
        <div>
          <h3 className="text-lg font-bold text-slate-900">Expense Ratio Impact Simulator</h3>
          <p className="text-xs text-slate-500">Visualize how small costs compound over time to eat into your wealth.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-0">

        {/* LEFT: CONTROLS */}
        <div className="lg:col-span-4 p-6 border-r border-slate-100 bg-white space-y-6">

            {/* Amount */}
            <div>
                <label className="flex justify-between text-xs font-bold text-slate-500 uppercase mb-2">
                    <span>Investment Amount</span>
                    <span className="text-slate-900">{formatCurrency(initialInvestment)}</span>
                </label>
                <input 
                    type="range" min="10000" max="5000000" step="10000" 
                    value={initialInvestment} onChange={(e) => setInitialInvestment(Number(e.target.value))}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-600"
                />
            </div>

            {/* Time Horizon */}
            <div>
                <label className="flex justify-between text-xs font-bold text-slate-500 uppercase mb-2">
                    <span>Time Horizon</span>
                    <span className="text-slate-900">{years} Years</span>
                </label>
                <input 
                    type="range" min="1" max="40" step="1" 
                    value={years} onChange={(e) => setYears(Number(e.target.value))}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-600"
                />
            </div>

            {/* Expected Return */}
            <div>
                <label className="flex justify-between text-xs font-bold text-slate-500 uppercase mb-2">
                    <span>Expected Market Return (CAGR)</span>
                    <span className="text-slate-900">{expectedReturn}%</span>
                </label>
                <input 
                    type="range" min="5" max="25" step="0.5" 
                    value={expectedReturn} onChange={(e) => setExpectedReturn(Number(e.target.value))}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-emerald-600"
                />
            </div>

            <div className="pt-4 border-t border-slate-100">
                <p className="text-xs font-semibold text-slate-400 mb-3 uppercase">Expense Ratios (TER)</p>

                {/* Direct TER */}
                <div className="mb-4">
                    <label className="flex justify-between text-xs font-medium text-emerald-700 mb-1">
                        <span>Direct Plan TER</span>
                        <span className="font-bold">{directTER}%</span>
                    </label>
                    <input 
                        type="range" min="0.1" max="3.0" step="0.1" 
                        value={directTER} onChange={(e) => setDirectTER(Number(e.target.value))}
                        className="w-full h-1.5 bg-emerald-100 rounded-lg appearance-none cursor-pointer accent-emerald-600"
                    />
                </div>

                {/* Regular TER */}
                <div>
                    <label className="flex justify-between text-xs font-medium text-blue-700 mb-1">
                        <span>Regular Plan TER</span>
                        <span className="font-bold">{regularTER}%</span>
                    </label>
                    <input 
                        type="range" min="0.1" max="3.0" step="0.1" 
                        value={regularTER} onChange={(e) => setRegularTER(Number(e.target.value))}
                        className="w-full h-1.5 bg-blue-100 rounded-lg appearance-none cursor-pointer accent-blue-600"
                    />
                </div>
            </div>

            <div className="bg-orange-50 border border-orange-100 p-3 rounded-lg flex gap-3 text-xs text-orange-800">
                 <AlertTriangle size={16} className="flex-shrink-0 mt-0.5" />
                 <p>
                    A {Math.abs(regularTER - directTER).toFixed(2)}% difference in fees results in 
                    <strong> {percentageLost.toFixed(1)}% less wealth</strong> over {years} years.
                 </p>
            </div>
        </div>

        {/* RIGHT: CHART & STATS */}
        <div className="lg:col-span-8 p-6 bg-white flex flex-col">

             {/* Big Numbers */}
             <div className="grid grid-cols-2 gap-4 mb-6">
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                    <p className="text-xs text-slate-500 font-bold uppercase mb-1">Wealth with Regular Plan</p>
                    <p className="text-xl font-bold text-blue-600">{formatCurrency(finalStats.regularValue)}</p>
                </div>
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 relative overflow-hidden">
                    <div className="relative z-10">
                        <p className="text-xs text-slate-500 font-bold uppercase mb-1">Wealth Lost to Commissions</p>
                        <p className="text-xl font-bold text-red-500">{formatCurrency(totalLoss)}</p>
                    </div>
                    <div className="absolute right-0 top-0 bottom-0 w-1/3 bg-gradient-to-l from-red-50 to-transparent pointer-events-none"></div>
                </div>
             </div>

             {/* Chart */}
             <div className="flex-1 w-full min-h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={data} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                        <defs>
                            <linearGradient id="splitColorDirect" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor={COLORS.direct} stopOpacity={0.1}/>
                                <stop offset="95%" stopColor={COLORS.direct} stopOpacity={0}/>
                            </linearGradient>
                            <linearGradient id="splitColorRegular" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor={COLORS.regular} stopOpacity={0.1}/>
                                <stop offset="95%" stopColor={COLORS.regular} stopOpacity={0}/>
                            </linearGradient>
                        </defs>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis 
                            dataKey="year" 
                            tick={{fontSize: 10, fill: '#94a3b8'}} 
                            tickLine={false} 
                            axisLine={false} 
                            label={{ value: 'Years Invested', position: 'insideBottom', offset: -5, fontSize: 10, fill: '#94a3b8' }}
                        />
                        <YAxis 
                            tickFormatter={(val) => `₹${(val/100000).toFixed(0)}L`} 
                            tick={{fontSize: 10, fill: '#94a3b8'}} 
                            tickLine={false} 
                            axisLine={false} 
                        />
                        <Tooltip 
                            content={({ active, payload, label }) => {
                                if (active && payload && payload.length) {
                                return (
                                    <div className="bg-white p-3 border border-slate-100 shadow-xl rounded-lg text-xs">
                                        <p className="font-bold text-slate-700 mb-2">Year {label}</p>
                                        <p className="text-emerald-600 mb-1">
                                            Direct: <span className="font-bold">{formatCurrency(payload[0].value as number)}</span>
                                        </p>
                                        <p className="text-blue-600 mb-2">
                                            Regular: <span className="font-bold">{formatCurrency(payload[1].value as number)}</span>
                                        </p>
                                        <div className="pt-2 border-t border-slate-100">
                                            <p className="text-red-500">
                                                Lost: <span className="font-bold">{formatCurrency((payload[0].value as number) - (payload[1].value as number))}</span>
                                            </p>
                                        </div>
                                    </div>
                                );
                                }
                                return null;
                            }}
                        />
                        <Legend wrapperStyle={{fontSize: '12px', paddingTop: '10px'}}/>
                        <Area 
                            type="monotone" 
                            dataKey="directValue" 
                            name="Direct Plan (Low TER)"
                            stroke={COLORS.direct} 
                            strokeWidth={2}
                            fill="url(#splitColorDirect)" 
                        />
                        <Area 
                            type="monotone" 
                            dataKey="regularValue" 
                            name="Regular Plan (High TER)"
                            stroke={COLORS.regular} 
                            strokeWidth={2}
                            fill="url(#splitColorRegular)" 
                        />
                    </AreaChart>
                </ResponsiveContainer>
             </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
